function isExternos() {
    return (window.currentUserRole || currentRole || '').toLowerCase() === 'externos';
}

function isCalidad() {
    return (window.currentUserRole || currentRole || '').toLowerCase() === 'calidad';
}

function canAccessQualityControl() {
    const role = (window.currentUserRole || currentRole || '').toLowerCase();
    return role === 'admin' || role === 'calidad';
}

function formatRoleLabel(role) {
    const normalized = String(role || '').toLowerCase().trim();
    if (normalized === 'user') return 'O. Tecnica';
    if (normalized === 'admin') return 'Admin';
    if (normalized === 'calidad') return 'Calidad';
    if (normalized === 'externos') return 'Externos';
    return role || '';
}

function normalizeCardTitle(value) {
    return String(value || '')
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .toLowerCase()
        .trim();
}

function showRoleRestrictionMessage(message) {
    if (typeof showNotification === 'function') {
        showNotification(message, 'error');
    } else {
        alert(message);
    }
}

function snapshotDashboardCard(card) {
    if (!card || card.dataset.snapshotReady === 'true') return;

    const statusEl = card.querySelector('.card-status');
    card.dataset.snapshotReady = 'true';
    card.dataset.origOnclick = card.getAttribute('onclick') || '';
    card.dataset.origMode = card.classList.contains('active-card') ? 'active' : 'deactivated';
    card.dataset.origStatus = statusEl ? statusEl.textContent : '';
}

function restoreDashboardCard(card) {
    if (!card) return;

    snapshotDashboardCard(card);

    const statusEl = card.querySelector('.card-status');
    card.onclick = null;

    if (card.dataset.origOnclick) card.setAttribute('onclick', card.dataset.origOnclick);
    else card.removeAttribute('onclick');

    card.classList.remove('active-card', 'deactivated');
    card.classList.add(card.dataset.origMode === 'active' ? 'active-card' : 'deactivated');
    if (statusEl) statusEl.textContent = card.dataset.origStatus || '';
    card.style.cursor = '';
}

function restrictDashboardCard(card, message, statusText = 'Restringido') {
    if (!card) return;

    snapshotDashboardCard(card);

    const statusEl = card.querySelector('.card-status');
    card.removeAttribute('onclick');
    card.classList.remove('active-card');
    card.classList.add('deactivated');
    card.style.cursor = 'not-allowed';
    if (statusEl) statusEl.textContent = statusText;
    card.onclick = (event) => {
        event.preventDefault();
        event.stopPropagation();
        showRoleRestrictionMessage(message);
        return false;
    };
}

function applyExternosHomeRestrictions() {
    if (!isExternos()) return;

    const home = document.getElementById('view-home');
    if (!home) return;

    const cards = Array.from(home.querySelectorAll('.dashboard-card'));
    if (!cards.length) return;

    cards.forEach(card => {
        const titleEl = card.querySelector('.card-title');
        const normalizedTitle = normalizeCardTitle(titleEl ? titleEl.textContent : '');
        const allowTitles = ['herramientas'];
        const isAllowed = allowTitles.some((title) => normalizedTitle.includes(title));

        if (!isAllowed) {
            restrictDashboardCard(card, 'Acceso restringido para usuarios externos', 'Desactivado');
        }
    });
}

function applyCalidadRestrictions() {
    if (!isCalidad()) return;

    const home = document.getElementById('view-home');
    if (home) {
        const cards = Array.from(home.querySelectorAll('.dashboard-card'));
        const allowedHomeTitles = new Set(['registros']);

        cards.forEach((card) => {
            const titleEl = card.querySelector('.card-title');
            const normalizedTitle = normalizeCardTitle(titleEl ? titleEl.textContent : '');
            const isAllowed = allowedHomeTitles.has(normalizedTitle);

            if (!isAllowed) {
                restrictDashboardCard(card, 'Acceso restringido para usuarios de Calidad');
            }
        });
    }

    const registrosHome = document.getElementById('view-home-registros');
    if (!registrosHome) return;

    const registroCards = Array.from(registrosHome.querySelectorAll('.dashboard-card'));
    const allowedRegistroTitles = new Set([
        'registro de actividad',
        'registro de control de calidad'
    ]);

    registroCards.forEach((card) => {
        const titleEl = card.querySelector('.card-title');
        const normalizedTitle = normalizeCardTitle(titleEl ? titleEl.textContent : '');
        const isAllowed = allowedRegistroTitles.has(normalizedTitle);

        if (!isAllowed) {
            restrictDashboardCard(card, 'Acceso restringido para usuarios de Calidad');
        }
    });
}

function applyRoleHomeRestrictions() {
    ['view-home', 'view-home-registros'].forEach((viewId) => {
        const view = document.getElementById(viewId);
        if (!view) return;

        Array.from(view.querySelectorAll('.dashboard-card')).forEach((card) => {
            restoreDashboardCard(card);
        });
    });

    applyExternosHomeRestrictions();
    applyCalidadRestrictions();

    const registrosHome = document.getElementById('view-home-registros');
    if (!registrosHome) return;

    const registroCards = Array.from(registrosHome.querySelectorAll('.dashboard-card'));
    registroCards.forEach((card) => {
        const titleEl = card.querySelector('.card-title');
        const normalizedTitle = normalizeCardTitle(titleEl ? titleEl.textContent : '');
        if (normalizedTitle === 'registro de control de calidad' && !canAccessQualityControl()) {
            restrictDashboardCard(card, 'Acceso restringido al panel de Calidad', 'Desactivado');
        }
    });
}


