let qualityCacheRefreshPromise = null;
let qualityCacheLastRefreshAt = 0;

function refreshQualityCsvCache(force = false) {
    const now = Date.now();
    if (!force && qualityCacheRefreshPromise && (now - qualityCacheLastRefreshAt) < 15000) {
        return qualityCacheRefreshPromise;
    }

    qualityCacheLastRefreshAt = now;
    qualityCacheRefreshPromise = fetch('/api/quality/cache/refresh', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' }
    })
        .then((response) => response.json().catch(() => ({})))
        .catch((error) => {
            console.warn('Quality CSV cache refresh failed:', error);
            return null;
        })
        .finally(() => {
            window.setTimeout(() => {
                qualityCacheRefreshPromise = null;
            }, 2500);
        });

    return qualityCacheRefreshPromise;
}

