function formatQualityQuantity(value) {
    const num = Number(value || 0);
    if (!Number.isFinite(num)) return '0';
    return Number.isInteger(num) ? String(num) : num.toLocaleString('es-AR', { maximumFractionDigits: 2 });
}

function escapeQualityHtml(value) {
    return String(value ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

function getQualityProgressColor(progressPct) {
    const pct = Number(progressPct || 0);
    if (pct >= 100) return '#2ecc71';
    if (pct < 20) return '#e74c3c';
    return '#f1c40f';
}

function autoResizeQualityObservationInput(textarea) {
    if (!(textarea instanceof HTMLTextAreaElement)) return;
    textarea.style.height = 'auto';
    textarea.style.height = `${Math.max(textarea.scrollHeight, 34)}px`;
}

function syncQualityObservationInMemory(item, produc, observacion) {
    const normalizedItem = String(item || '').trim();
    const normalizedProduc = String(produc || '').trim();
    const applyUpdate = (record) => {
        if (String(record?.item || '').trim() === normalizedItem && String(record?.produc || '').trim() === normalizedProduc) {
            record.observaciones = observacion;
        }
    };

    (window._qualityPendingRecords || []).forEach(applyUpdate);
    (window._qualityHistoryRecords || []).forEach(applyUpdate);
}

async function saveQualityObservationInput(textarea) {
    if (!(textarea instanceof HTMLTextAreaElement)) return;

    const item = textarea.dataset.item || '';
    const produc = textarea.dataset.produc || '';
    const observacion = textarea.value || '';
    const lastSaved = textarea.dataset.lastSaved || '';
    if (observacion === lastSaved) return;

    textarea.disabled = true;
    textarea.style.opacity = '0.75';

    try {
        const response = await fetch('/api/quality/observation', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ item, produc, observacion })
        });
        const data = await response.json();
        if (!response.ok || data.status !== 'success') {
            throw new Error(data.message || 'No se pudo guardar la observacion.');
        }

        textarea.dataset.lastSaved = observacion;
        textarea.style.borderColor = '#2ecc71';
        syncQualityObservationInMemory(item, produc, observacion);
        window.setTimeout(() => {
            if (textarea.isConnected) textarea.style.borderColor = 'var(--border)';
        }, 900);
    } catch (error) {
        console.error('Error saving quality observation:', error);
        textarea.style.borderColor = '#e74c3c';
        showNotification(error.message || 'No se pudo guardar la observacion.', 'error');
    } finally {
        textarea.disabled = false;
        textarea.style.opacity = '1';
    }
}

function bindQualityObservationInputs(scope) {
    if (!scope) return;
    scope.querySelectorAll('.quality-observation-input').forEach((textarea) => {
        autoResizeQualityObservationInput(textarea);
        if (textarea.dataset.bound === '1') return;
        textarea.dataset.lastSaved = textarea.value || '';
        textarea.addEventListener('input', () => autoResizeQualityObservationInput(textarea));
        textarea.addEventListener('blur', () => saveQualityObservationInput(textarea));
        textarea.dataset.bound = '1';
    });
}

function qualityHexToRgba(hex, alpha = 0.16) {
    const normalized = String(hex || '').trim();
    const match = normalized.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
    if (!match) return `rgba(74,163,255,${alpha})`;
    return `rgba(${parseInt(match[1], 16)}, ${parseInt(match[2], 16)}, ${parseInt(match[3], 16)}, ${alpha})`;
}

function getQualityPendingCategoryById(categoryId) {
    return (currentQualityPendingCategories || []).find((category) => String(category?.id || '') === String(categoryId || '')) || null;
}

function getQualityPendingAssignedCategoryId(record) {
    const rowKey = String(record?.row_key || '').trim();
    if (!rowKey) return '';
    return String((currentQualityPendingCategoryAssignments || {})[rowKey] || '').trim();
}

function handleQualityPendingCategoryDragStart(event, categoryId) {
    currentQualityPendingDraggedCategoryId = String(categoryId || '').trim();
    if (event?.dataTransfer) {
        event.dataTransfer.effectAllowed = 'move';
        event.dataTransfer.setData('text/plain', currentQualityPendingDraggedCategoryId);
    }
}

function handleQualityPendingCategoryDragEnd() {
    currentQualityPendingDraggedCategoryId = '';
    document.querySelectorAll('#quality-pending-table tbody tr[data-row-key]').forEach((row) => {
        row.style.boxShadow = '';
        row.style.transform = '';
    });
}

function handleQualityPendingRowDragOver(event) {
    if (!currentQualityPendingDraggedCategoryId) return;
    event.preventDefault();
    if (event?.dataTransfer) event.dataTransfer.dropEffect = 'move';
}

function handleQualityPendingRowDragEnter(event) {
    if (!currentQualityPendingDraggedCategoryId) return;
    const row = event?.currentTarget;
    if (!row) return;
    row.style.boxShadow = 'inset 0 0 0 2px var(--bpb-blue)';
    row.style.transform = 'translateY(-1px)';
}

function handleQualityPendingRowDragLeave(event) {
    const row = event?.currentTarget;
    if (!row) return;
    row.style.boxShadow = '';
    row.style.transform = '';
}

async function handleQualityPendingRowDrop(event, rowKey) {
    if (!currentQualityPendingDraggedCategoryId || !rowKey) return;
    event.preventDefault();
    const row = event?.currentTarget;
    if (row) {
        row.style.boxShadow = '';
        row.style.transform = '';
    }
    const categoryId = currentQualityPendingDraggedCategoryId === QUALITY_PENDING_UNCATEGORIZED_FILTER_ID
        ? ''
        : currentQualityPendingDraggedCategoryId;
    currentQualityPendingDraggedCategoryId = '';
    await assignQualityPendingCategory(rowKey, categoryId);
}

function renderQualityPendingCategoryPills() {
    const container = document.getElementById('quality-pending-category-pills');
    if (!container) return;

    const categories = Array.isArray(currentQualityPendingCategories) ? currentQualityPendingCategories : [];
    const hiddenCategory = categories.find((category) => String(category?.id || '') === QUALITY_PENDING_HIDDEN_CATEGORY_ID) || null;
    const regularCategories = categories.filter((category) => String(category?.id || '') !== QUALITY_PENDING_HIDDEN_CATEGORY_ID);
    const pills = [
        { id: 'all', name: 'Todos', color: '' },
        ...(hiddenCategory ? [hiddenCategory] : []),
        { id: QUALITY_PENDING_UNCATEGORIZED_FILTER_ID, name: 'Sin Categoria', color: '#8b949e' },
        ...regularCategories
    ];

    container.innerHTML = pills.map((category) => {
        const isActive = String(currentQualityPendingFilter || 'all') === String(category.id || 'all');
        const color = category.color || '';
        const style = isActive
            ? `background:${color || 'var(--bpb-blue)'}; color:#fff; border-color:${color || 'var(--bpb-blue)'};`
            : (color ? `border-color:${color}; color:${color}; background:${qualityHexToRgba(color, 0.12)};` : '');
        const buttonId = escapeQualityHtml(String(category.id || 'all'));
        const draggable = String(category.id || '') !== 'all' ? 'true' : 'false';
        const dragHint = String(category.id || '') !== 'all' ? ' title="Arrastra esta categoria hacia una fila"' : '';
        return `<button class="filter-pill ${isActive ? 'active' : ''}" data-quality-filter="${buttonId}" draggable="${draggable}" style="${style}"${dragHint}>${escapeQualityHtml(category.name || 'Todos')}</button>`;
    }).join('');

    container.querySelectorAll('[data-quality-filter]').forEach((button) => {
        const categoryId = button.getAttribute('data-quality-filter') || 'all';
        button.addEventListener('click', () => {
            setQualityPendingFilter(categoryId);
        });
        if (categoryId !== 'all') {
            button.addEventListener('dragstart', (event) => handleQualityPendingCategoryDragStart(event, categoryId));
            button.addEventListener('dragend', handleQualityPendingCategoryDragEnd);
        }
    });
}

async function loadQualityPendingCategories() {
    try {
        const response = await fetch('/api/quality/pending-categories');
        const data = await response.json();
        if (!response.ok || data.status !== 'success') {
            throw new Error(data.message || 'No se pudieron cargar las categorias.');
        }

        currentQualityPendingCategories = Array.isArray(data.data?.categories) ? data.data.categories : [];
        currentQualityPendingCategoryAssignments = data.data?.assignments && typeof data.data.assignments === 'object'
            ? data.data.assignments
            : {};

        if (
            currentQualityPendingFilter !== 'all' &&
            currentQualityPendingFilter !== QUALITY_PENDING_UNCATEGORIZED_FILTER_ID &&
            !currentQualityPendingCategories.some((category) => String(category?.id || '') === String(currentQualityPendingFilter))
        ) {
            currentQualityPendingFilter = 'all';
        }
        renderQualityPendingCategoryPills();
        if (Array.isArray(window._qualityPendingRecords)) renderQualityPendingTable();
    } catch (error) {
        console.error('Error loading quality pending categories:', error);
        currentQualityPendingCategories = [];
        currentQualityPendingCategoryAssignments = {};
        currentQualityPendingFilter = 'all';
        renderQualityPendingCategoryPills();
    }
}

function renderQualityPendingCategoriesManagerContent(box) {
    if (!box) return;

    const categories = Array.isArray(currentQualityPendingCategories) ? currentQualityPendingCategories : [];
    box.innerHTML = `
        <div style="display:flex; justify-content:space-between; align-items:center; gap:16px; margin-bottom:16px;">
            <div>
                <h3 style="margin:0; color:var(--bpb-blue);">Categorias</h3>
                <div style="color:var(--text-secondary); font-size:0.9rem; margin-top:4px;">Crear, editar o eliminar categorias para pintar filas de pendientes.</div>
            </div>
            <button class="btn" data-close-categories>&times;</button>
        </div>
        <div style="display:flex; flex-direction:column; gap:12px; max-height:48vh; overflow-y:auto; margin-bottom:18px;">
            ${categories.length ? categories.map((category) => `
                <div style="display:grid; grid-template-columns:minmax(0,1fr) 52px 96px 96px; gap:10px; align-items:center; background:rgba(255,255,255,0.03); border:1px solid var(--border); border-radius:10px; padding:10px;">
                    <input type="text" value="${escapeQualityHtml(category.name || '')}" data-category-name="${escapeQualityHtml(category.id)}" class="search-input" style="width:100%; min-width:0; box-sizing:border-box;" ${String(category.id) === QUALITY_PENDING_HIDDEN_CATEGORY_ID ? 'readonly' : ''}>
                    <input type="color" value="${escapeQualityHtml(category.color || '#4aa3ff')}" data-category-color="${escapeQualityHtml(category.id)}" style="width:52px; min-width:52px; height:38px; border:none; background:none; padding:0; cursor:pointer; box-sizing:border-box;">
                    <button class="btn" data-save-category="${escapeQualityHtml(category.id)}" style="width:96px;">Guardar</button>
                    ${String(category.id) === QUALITY_PENDING_HIDDEN_CATEGORY_ID
                        ? '<button class="btn" disabled style="width:96px; opacity:0.5; cursor:not-allowed;">Sistema</button>'
                        : `<button class="btn" data-delete-category="${escapeQualityHtml(category.id)}" style="width:96px; border-color:var(--bpb-blue); color:var(--bpb-blue); background:transparent;">Borrar</button>`}
                </div>
            `).join('') : '<div style="padding:14px; border:1px dashed var(--border); border-radius:10px; color:var(--text-secondary);">No hay categorias creadas.</div>'}
        </div>
        <div style="border-top:1px solid var(--border); padding-top:16px; display:grid; grid-template-columns:minmax(0,1fr) auto auto; gap:10px; align-items:center;">
            <input type="text" id="quality-new-category-name" class="search-input" placeholder="Nombre de la categoria">
            <input type="color" id="quality-new-category-color" value="#4aa3ff" style="width:44px; height:38px; border:none; background:none; padding:0; cursor:pointer;">
            <button class="btn" id="quality-create-category-btn">Crear</button>
        </div>
    `;

    box.querySelector('[data-close-categories]')?.addEventListener('click', () => {
        box.closest('.quality-category-overlay')?.remove();
    });
    box.querySelectorAll('[data-save-category]').forEach((button) => {
        button.addEventListener('click', async () => {
            const categoryId = button.getAttribute('data-save-category') || '';
            const name = box.querySelector(`[data-category-name="${categoryId}"]`)?.value || '';
            const color = box.querySelector(`[data-category-color="${categoryId}"]`)?.value || '#4aa3ff';
            try {
                const response = await fetch(`/api/quality/pending-categories/${encodeURIComponent(categoryId)}`, {
                    method: 'PUT',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ name, color })
                });
                const data = await response.json();
                if (!response.ok || data.status !== 'success') throw new Error(data.message || 'No se pudo actualizar la categoria.');
                await loadQualityPendingCategories();
                renderQualityPendingCategoriesManagerContent(box);
                showNotification('Categoria actualizada.', 'success');
            } catch (error) {
                showNotification(error.message || 'No se pudo actualizar la categoria.', 'error');
            }
        });
    });
    box.querySelectorAll('[data-delete-category]').forEach((button) => {
        const applyDeleteIdleState = () => {
            button.style.borderColor = 'var(--bpb-blue)';
            button.style.color = 'var(--bpb-blue)';
            button.style.background = 'transparent';
        };
        const applyDeleteHoverState = () => {
            button.style.borderColor = 'var(--bpb-blue)';
            button.style.color = '#fff';
            button.style.background = 'var(--bpb-blue)';
        };
        applyDeleteIdleState();
        button.addEventListener('mouseenter', applyDeleteHoverState);
        button.addEventListener('mouseleave', applyDeleteIdleState);
        button.addEventListener('click', async () => {
            const categoryId = button.getAttribute('data-delete-category') || '';
            const assignedCount = Object.values(currentQualityPendingCategoryAssignments || {}).filter((assignedId) => String(assignedId || '') === String(categoryId)).length;
            const confirmed = await confirmQualityCategoryDeletion(assignedCount);
            if (!confirmed) return;
            try {
                const response = await fetch(`/api/quality/pending-categories/${encodeURIComponent(categoryId)}`, { method: 'DELETE' });
                const data = await response.json();
                if (!response.ok || data.status !== 'success') throw new Error(data.message || 'No se pudo borrar la categoria.');
                await loadQualityPendingCategories();
                renderQualityPendingCategoriesManagerContent(box);
                showNotification('Categoria eliminada.', 'success');
            } catch (error) {
                showNotification(error.message || 'No se pudo borrar la categoria.', 'error');
            }
        });
    });
    box.querySelector('#quality-create-category-btn')?.addEventListener('click', async () => {
        const name = box.querySelector('#quality-new-category-name')?.value || '';
        const color = box.querySelector('#quality-new-category-color')?.value || '#4aa3ff';
        try {
            const response = await fetch('/api/quality/pending-categories', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name, color })
            });
            const data = await response.json();
            if (!response.ok || data.status !== 'success') throw new Error(data.message || 'No se pudo crear la categoria.');
            await loadQualityPendingCategories();
            renderQualityPendingCategoriesManagerContent(box);
            showNotification('Categoria creada.', 'success');
        } catch (error) {
            showNotification(error.message || 'No se pudo crear la categoria.', 'error');
        }
    });
}

function confirmQualityCategoryDeletion(assignedCount) {
    return new Promise((resolve) => {
        const overlay = document.createElement('div');
        overlay.style.position = 'fixed';
        overlay.style.inset = '0';
        overlay.style.background = 'rgba(0,0,0,0.72)';
        overlay.style.zIndex = '4300';
        overlay.style.display = 'flex';
        overlay.style.alignItems = 'center';
        overlay.style.justifyContent = 'center';
        overlay.style.padding = '24px';

        const box = document.createElement('div');
        box.style.width = 'min(460px, 100%)';
        box.style.background = '#111';
        box.style.border = '1px solid var(--border)';
        box.style.borderRadius = '14px';
        box.style.padding = '20px';
        box.style.boxShadow = '0 20px 45px rgba(0,0,0,0.45)';
        box.innerHTML = `
            <div style="font-size:1.15rem; font-weight:700; color:var(--text-primary); margin-bottom:10px;">Eliminar Categoria</div>
            <div style="color:var(--text-secondary); line-height:1.5; margin-bottom:18px;">
                Existen ${assignedCount} Ingresos con dicha categoria, aun desea eliminarla?
            </div>
            <div style="display:flex; justify-content:flex-end; gap:10px;">
                <button class="btn" data-cancel-delete>Cancelar</button>
                <button class="btn" data-confirm-delete style="border-color:var(--bpb-blue); color:#fff; background:var(--bpb-blue);">Eliminar</button>
            </div>
        `;

        const close = (result) => {
            overlay.remove();
            resolve(result);
        };

        box.querySelector('[data-cancel-delete]')?.addEventListener('click', () => close(false));
        box.querySelector('[data-confirm-delete]')?.addEventListener('click', () => close(true));
        overlay.addEventListener('click', (event) => {
            if (event.target === overlay) close(false);
        });
        overlay.appendChild(box);
        document.body.appendChild(overlay);
    });
}

function openQualityPendingCategoriesManager() {
    const overlay = document.createElement('div');
    overlay.className = 'quality-category-overlay';
    overlay.style.position = 'fixed';
    overlay.style.inset = '0';
    overlay.style.background = 'rgba(0,0,0,0.72)';
    overlay.style.zIndex = '4100';
    overlay.style.display = 'flex';
    overlay.style.alignItems = 'center';
    overlay.style.justifyContent = 'center';
    overlay.style.padding = '24px';

    const box = document.createElement('div');
    box.style.width = 'min(760px, 100%)';
    box.style.maxHeight = '85vh';
    box.style.overflow = 'hidden';
    box.style.background = '#111';
    box.style.border = '1px solid var(--border)';
    box.style.borderRadius = '14px';
    box.style.padding = '18px';
    box.style.boxShadow = '0 20px 45px rgba(0,0,0,0.45)';

    renderQualityPendingCategoriesManagerContent(box);
    overlay.appendChild(box);
    overlay.addEventListener('click', (event) => {
        if (event.target === overlay) overlay.remove();
    });
    document.body.appendChild(overlay);
}

async function assignQualityPendingCategory(rowKey, categoryId) {
    try {
        const response = await fetch('/api/quality/pending-categories/assign', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ row_key: rowKey, category_id: categoryId || '' })
        });
        const data = await response.json();
    if (!response.ok || data.status !== 'success') throw new Error(data.message || 'No se pudo asignar la categoria.');
        if (categoryId) currentQualityPendingCategoryAssignments[rowKey] = categoryId;
        else delete currentQualityPendingCategoryAssignments[rowKey];
        renderQualityPendingTable();
        const category = getQualityPendingCategoryById(categoryId);
        if (category) {
            showNotification(`Categoria "${category.name}" asignada.`, 'success');
        } else if (!categoryId) {
            showNotification('Categoria quitada.', 'success');
        }
    } catch (error) {
        showNotification(error.message || 'No se pudo asignar la categoria.', 'error');
    }
}

function setQualityTableColumnWidths(tableSelector, widths) {
    const table = document.querySelector(tableSelector);
    if (!table) return;
    table.style.width = '100%';
    table.style.tableLayout = 'fixed';

    let colgroup = table.querySelector('colgroup');
    if (!colgroup) {
        colgroup = document.createElement('colgroup');
        table.insertBefore(colgroup, table.firstChild);
    }
    colgroup.innerHTML = widths.map((width) => `<col style="width:${width};">`).join('');
}

async function assignQualityPendingHandler(rowKey) {
    const handlerName = String(currentDisplayName || currentUser || 'Usuario').trim();
    if (!rowKey || !handlerName) return;

    try {
        const response = await fetch('/api/quality/pending-handler', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ row_key: rowKey, name: handlerName })
        });
        const data = await response.json();
        if (!response.ok || data.status !== 'success') throw new Error(data.message || 'No se pudo asignar el encargado.');

        if (Array.isArray(window._qualityPendingRecords)) {
            window._qualityPendingRecords = window._qualityPendingRecords.map((record) => (
                String(record?.row_key || '') === String(rowKey)
                    ? { ...record, encargado: handlerName, encargado_updated_at: data?.data?.updated_at || '' }
                    : record
            ));
        }
        renderQualityPendingTable();
        showNotification('Encargado asignado.', 'success');
    } catch (error) {
        showNotification(error.message || 'No se pudo asignar el encargado.', 'error');
    }
}

