function normalizeCotizacionIndiceFromComplementarioUnit(rawValue = '') {
    const raw = String(rawValue || '').trim();
    if (!raw) return '';

    const normalized = raw.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    const compact = normalized.toUpperCase().replace(/\s+/g, '').replace(/\./g, '');

    const aliases = {
        'C/UNO': 'Unidades',
        'C/1': 'Unidades',
        'CUNO': 'Unidades',
        'UNI': 'Unidades',
        'UND': 'Unidades',
        'UN': 'Unidades',
        'UNIDAD': 'Unidades',
        'UNIDADES': 'Unidades',
        'MTS': 'Metros',
        'MT': 'Metros',
        'METRO': 'Metros',
        'METROS': 'Metros',
        'KG': 'Kilogramos',
        'KGS': 'Kilogramos',
        'KILOGRAMO': 'Kilogramos',
        'KILOGRAMOS': 'Kilogramos',
        'FT': 'Pies',
        'PIE': 'Pies',
        'PIES': 'Pies',
        'LTS': 'Litros',
        'LT': 'Litros',
        'LITRO': 'Litros',
        'LITROS': 'Litros',
        'TN': 'Toneladas',
        'TON': 'Toneladas',
        'TONELADA': 'Toneladas',
        'TONELADAS': 'Toneladas',
        'MM': 'Milimetros',
        'MILIMETRO': 'Milimetros',
        'MILIMETROS': 'Milimetros',
        'MT3': 'Metros Cubicos',
        'MTS3': 'Metros Cubicos',
        'M3': 'Metros Cubicos',
        'METROCUBICO': 'Metros Cubicos',
        'METROSCUBICOS': 'Metros Cubicos',
        'MTS2': 'Metros Cuadrados',
        'MT2': 'Metros Cuadrados',
        'M2': 'Metros Cuadrados',
        'METROCUADRADO': 'Metros Cuadrados',
        'METROSCUADRADOS': 'Metros Cuadrados',
        'HORA': 'Horas',
        'HORAS': 'Horas',
        'MINUTO': 'Minutos',
        'MINUTOS': 'Minutos',
        'SEGUNDO': 'Segundos',
        'SEGUNDOS': 'Segundos',
        'CENTIMETRO': 'Centimetros',
        'CENTIMETROS': 'Centimetros',
        'CM': 'Centimetros',
        'GRAMO': 'Gramos',
        'GRAMOS': 'Gramos',
        'GR': 'Gramos',
        'G': 'Gramos'
    };

    if (aliases[compact]) return aliases[compact];

    const direct = COTIZACION_INDICE_OPTIONS.find((optionValue) => String(optionValue || '').trim().toLowerCase() === raw.toLowerCase());
    return direct || raw;
}

function isCotizacionTimeIndiceCategory(categoryKey) {
    return COTIZACION_SUBCONCEPTO_AUTO_HORA_CATEGORIES.has(sanitizeCotizacionCategory(categoryKey));
}

function getCotizacionIndiceOptionsForCategory(categoryKey) {
    if (isCotizacionTimeIndiceCategory(categoryKey)) {
        return ['Horas', 'Minutos', 'Segundos'];
    }
    return [...COTIZACION_INDICE_OPTIONS];
}

function getCotizacionIndiceConversionFactor(indiceValue = '') {
    const safeIndice = normalizeCotizacionIndiceFromComplementarioUnit(indiceValue);
    return Number(COTIZACION_TIME_UNIT_FACTORS[safeIndice] || 1);
}
