let adminUsersCache = [];
let qualityAdminStatsData = null;
let qualityAdminStatsYear = null;
let qualityAdminStatsStartMonth = null;
let qualityAdminStatsEndMonth = null;
let qualityAdminDayRangeStart = null;
let qualityAdminDayRangeEnd = null;
let qualityAdminAvailableUsers = [];
let qualityAdminSelectedUsers = [];
let qualityAdminUsersInitialized = false;
let qualityAdminProductQuery = '';
let qualityAdminSelectedProduct = '';
let qualityAdminSelectedProductRowKey = '';
let qualityAdminPrintState = null;

function buildQualityAdminNormalizedRecord(record, type) {
    const approvalDate = type === 'history' ? parseQualityFilterDate(record?.approval_date) : null;
    const ingressDate = parseQualityFilterDate(record?.fecha_ing_iso);
    const controlledQty = Number(record?.controlled_qty || 0);
    const totalQty = Number(record?.total_qty || 0);
    const progressPct = Number(record?.progress_pct || 0);
    const controlDays = Number(record?.control_days);

    return {
        ...record,
        _approvalTs: approvalDate ? approvalDate.getTime() : null,
        _approvalYear: approvalDate ? approvalDate.getFullYear() : null,
        _approvalMonth: approvalDate ? approvalDate.getMonth() : null,
        _ingressTs: ingressDate ? ingressDate.getTime() : null,
        _ingressYear: ingressDate ? ingressDate.getFullYear() : null,
        _ingressMonth: ingressDate ? ingressDate.getMonth() : null,
        _authorLower: String(record?.author || '').trim().toLowerCase(),
        _product: String(record?.produc || '').trim(),
        _controlledQty: Number.isFinite(controlledQty) ? controlledQty : 0,
        _totalQty: Number.isFinite(totalQty) ? totalQty : 0,
        _progressPct: Number.isFinite(progressPct) ? progressPct : 0,
        _controlDays: Number.isFinite(controlDays) ? controlDays : null
    };
}

function prepareAdminQualityStatsData(data) {
    const raw = data || {};
    return {
        ...raw,
        history_records: (Array.isArray(raw.history_records) ? raw.history_records : []).map((record) => buildQualityAdminNormalizedRecord(record, 'history')),
        pending_records: (Array.isArray(raw.pending_records) ? raw.pending_records : []).map((record) => buildQualityAdminNormalizedRecord(record, 'pending'))
    };
}

function resetAdminSections() {
    ['admin-home', 'admin-users-view', 'admin-stats-menu', 'admin-quality-stats-view'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = 'none';
    });
}

function setupAdminShell(opts = {}) {
    localStorage.setItem('lastView', 'admin');
    hideAllViews();

    const app = document.getElementById('app');
    if (app) app.style.display = 'block';

    const list = document.getElementById('view-list');
    if (list) list.style.display = 'none';
    const detail = document.getElementById('view-detail');
    if (detail) detail.style.display = 'none';
    const product = document.getElementById('view-product');
    if (product) product.style.display = 'none';

    const adminView = document.getElementById('view-admin');
    if (!adminView) return null;

    adminView.style.display = 'block';
    adminView.style.maxWidth = opts.maxWidth || '1000px';
    adminView.style.width = '100%';
    animateEntry('view-admin');

    const titleEl = document.getElementById('main-title');
    if (titleEl) {
        titleEl.innerHTML = opts.title || `<span class="breadcrumb-link" onclick="showHome()">Oficina T&eacute;cnica</span> <span style="color:var(--bpb-blue); margin: 0 10px;">&gt;</span> <span class="current" style="color:var(--text-primary);">Panel de Control</span>`;
    }

    const headerActions = document.getElementById('header-actions');
    if (headerActions) {
        const backAction = opts.backAction || 'showHome()';
        headerActions.style.display = 'flex';
        headerActions.style.alignItems = 'center';
        headerActions.style.gap = '10px';
        headerActions.style.flexWrap = 'nowrap';
        headerActions.innerHTML = `${opts.actionsHtml || ''}<button class="btn" onclick="${backAction}">&larr; Volver</button>`;
    }

    if (!document.getElementById('admin-upload-input')) {
        const input = document.createElement('input');
        input.type = 'file';
        input.id = 'admin-upload-input';
        input.accept = 'image/*';
        input.style.display = 'none';
        input.onchange = (e) => uploadProfilePicAdmin(e.target);
        document.body.appendChild(input);
    }

    return adminView;
}

