async function loadISOStatsData() {
    const range = getIsoStatsDateRange();
    return await buildISOStatsClient(range);
}

function normalizeIsoBp(value) {
    if (!value) return '';
    const s = String(value).trim().toUpperCase();
    const m = s.match(/BP[\s_-]*(\d{5})/);
    if (m) return `BP-${m[1]}`;
    return '';
}

function normalizeIsoKey(value) {
    if (!value) return '';
    return String(value).toUpperCase().replace(/[^A-Z0-9]/g, '');
}

function parseIsoEventDate(value) {
    if (!value) return null;
    const str = String(value).trim();
    if (!str) return null;
    if (str.includes('/')) {
        const parts = str.split('/');
        if (parts.length === 3) {
            if (parts[0].length === 4) {
                const d = new Date(parts[0], parts[1] - 1, parts[2]);
                return Number.isNaN(d.getTime()) ? null : d;
            }
            const d = new Date(parts[2], parts[1] - 1, parts[0]);
            return Number.isNaN(d.getTime()) ? null : d;
        }
    }
    if (str.includes('-')) {
        const parts = str.split('-');
        if (parts.length === 3) {
            if (parts[0].length === 4) {
                const d = new Date(parts[0], parts[1] - 1, parts[2]);
                return Number.isNaN(d.getTime()) ? null : d;
            }
            if (parts[2].length === 4) {
                const d = new Date(parts[2], parts[1] - 1, parts[0]);
                return Number.isNaN(d.getTime()) ? null : d;
            }
        }
    }
    const d = new Date(str);
    return Number.isNaN(d.getTime()) ? null : d;
}

async function buildISOStatsClient(range = {}) {
    const isoRes = await fetch('/api/iso-r01903-records');
    const isoData = await isoRes.json().catch(() => ({}));
    if (!isoRes.ok || !isoData || isoData.status !== 'success') {
        return { status: 'error', message: isoData && isoData.message ? isoData.message : 'No se pudo leer R019-03.' };
    }
    const isoRecords = Array.isArray(isoData.records) ? isoData.records : [];
    const startIso = range.start || '';
    const endIso = range.end || '';
    const startDate = startIso ? new Date(startIso) : null;
    const endDate = endIso ? new Date(endIso) : null;
    const inRange = (d) => {
        if (!startDate || !endDate || !d) return true;
        return d >= startDate && d <= endDate;
    };

    const filteredIsoRecords = isoRecords.filter(r => {
        if (!startDate || !endDate) return true;
        const d1 = parseIsoEventDate(r.fecha_inicio || r.fechaInicio || r.fecha || r.fecha_ingreso);
        const d2 = parseIsoEventDate(r.fecha_fin || r.fechaFin);
        return inRange(d1 || d2);
    });


    const bpList = [];
    const bpMap = {};
    const bpStatus = {};
    const seenBps = new Set();
    const statusCounts = { activo: 0, standby: 0, cerrado: 0 };
    const activeByEtapa = {};
    const standbyByEtapa = {};
    const closedBySituacion = {};
    const activeBps = [];
    const standbyBps = [];
    const closedBps = [];
    const openByEtapa = {};
    const openBySituacion = {};

    const classifyStatus = (situacion, isClosed) => {
        if (isClosed) return 'cerrado';
        const s = (situacion || '').toLowerCase();
        if (s.includes('stand') || s.includes('paus') || s.includes('susp')) return 'standby';
        return 'activo';
    };

    filteredIsoRecords.forEach(r => {
        const desc = (r.descripcion || '').trim();
        if (!desc) return;
        const norm = normalizeIsoBp(desc) || desc;
        const key = normalizeIsoKey(norm);
        bpList.push(norm);
        bpMap[normalizeIsoKey(norm)] = norm;
        bpMap[normalizeIsoKey(desc)] = norm;

        if (seenBps.has(key)) return;
        seenBps.add(key);

        const situacion = (r.situacion || '').trim();
        const etapa = (r.etapa || '').trim() || 'Sin etapa';
        const isClosed = !!(r.fecha_fin || '').trim();
        const status = classifyStatus(situacion, isClosed);
        bpStatus[norm] = status;

        if (status === 'cerrado') {
            statusCounts.cerrado += 1;
            closedBps.push(norm);
            const label = situacion || 'Cerrado';
            closedBySituacion[label] = (closedBySituacion[label] || 0) + 1;
            return;
        }

        openByEtapa[etapa] = (openByEtapa[etapa] || 0) + 1;
        const sitLabel = situacion || 'Sin situacion';
        openBySituacion[sitLabel] = (openBySituacion[sitLabel] || 0) + 1;

        if (status === 'standby') {
            statusCounts.standby += 1;
            standbyBps.push(norm);
            standbyByEtapa[etapa] = (standbyByEtapa[etapa] || 0) + 1;
        } else {
            statusCounts.activo += 1;
            activeBps.push(norm);
            activeByEtapa[etapa] = (activeByEtapa[etapa] || 0) + 1;
        }
    });

    const totalBps = seenBps.size;
    const openCount = statusCounts.activo + statusCounts.standby;
    const closedCount = statusCounts.cerrado;

    const userHours = {};
    const bpHours = {};
    const userBpHours = {};

    // base_datos_respuestas.csv: ProyectoFinal -> project, Tiempo -> hours, Nombre -> user
    let actUrl = '/api/activity-stats-global';
    const params = [];
    if (startIso) params.push(`start_date=${encodeURIComponent(startIso)}`);
    if (endIso) params.push(`end_date=${encodeURIComponent(endIso)}`);
    if (params.length) actUrl += '?' + params.join('&');
    const actRes = await fetch(actUrl);
    const actData = await actRes.json().catch(() => ({}));
    const actRecords = Array.isArray(actData.records) ? actData.records : [];

    actRecords.forEach(rec => {
        const user = (rec.user || 'Desconocido').trim();
        const proj = (rec.project || '').trim();
        const hours = Number(rec.hours) || 0;
        if (hours <= 0) return;
        let bp = normalizeIsoBp(proj);
        if (!bp) {
            const key = normalizeIsoKey(proj);
            bp = bpMap[key] || '';
        }
        if (!bp) return;
        userHours[user] = (userHours[user] || 0) + hours;
        bpHours[bp] = (bpHours[bp] || 0) + hours;
        const ubKey = `${user}||${bp}`;
        userBpHours[ubKey] = (userBpHours[ubKey] || 0) + hours;
    });

    const userHoursRows = Object.entries(userHours)
        .map(([user, hours]) => ({ user, hours: Math.round(hours * 100) / 100 }))
        .sort((a, b) => b.hours - a.hours);

    const bpHoursRows = Object.entries(bpHours)
        .map(([bp, hours]) => ({ bp, hours: Math.round(hours * 100) / 100 }))
        .sort((a, b) => b.hours - a.hours);

    const userBpRows = Object.entries(userBpHours)
        .map(([key, hours]) => {
            const [user, bp] = key.split('||');
            return { user, bp, hours: Math.round(hours * 100) / 100 };
        })
        .sort((a, b) => b.hours - a.hours);

    const etapaDurations = {};
    const areaStats = {};
    const empresaStats = {};
    const bpEtapaDurations = {};
    const allDurations = [];

    const uniqBps = Array.from(new Set(bpList));

    // Simple concurrency control
    const limit = 4;
    let idx = 0;
    const workers = new Array(limit).fill(0).map(async () => {
        while (idx < uniqBps.length) {
            const cur = uniqBps[idx++];
            const curBp = normalizeIsoBp(cur);
            if (!curBp) {
                continue;
            }
            try {
                const evRes = await fetch(`/api/iso-r01902-events?bp=${encodeURIComponent(curBp)}`);
                const evData = await evRes.json().catch(() => ({}));
                if (!evRes.ok || !evData || evData.status !== 'success') continue;
                const events = Array.isArray(evData.events) ? evData.events : [];
                if (!events.length) continue;

                const datesByEtapa = {};
                events.forEach(ev => {
                    const etapa = (ev.etapa || '').trim();
                    const fecha = parseIsoEventDate(ev.fecha);
                    if (startDate && endDate && fecha && (fecha < startDate || fecha > endDate)) {
                        return;
                    }
                    if (etapa && fecha) {
                    }
                    if (etapa && fecha) {
                        if (!datesByEtapa[etapa]) datesByEtapa[etapa] = [];
                        datesByEtapa[etapa].push(fecha);
                    }

                    const area = (ev.area || '').trim();
                    if (area) {
                        if (!areaStats[area]) areaStats[area] = { events: 0, bps: new Set() };
                        areaStats[area].events += 1;
                        areaStats[area].bps.add(curBp);
                    }

                    const empresa = (ev.empresa || '').trim();
                    if (empresa) {
                        if (!empresaStats[empresa]) empresaStats[empresa] = { events: 0, bps: new Set() };
                        empresaStats[empresa].events += 1;
                        empresaStats[empresa].bps.add(curBp);
                    }
                });

                const perBpDurations = {};

                Object.keys(datesByEtapa).forEach(etapa => {
                    const dates = datesByEtapa[etapa];
                    if (!dates || dates.length === 0) return;
                    const min = new Date(Math.min(...dates.map(d => d.getTime())));
                    const max = new Date(Math.max(...dates.map(d => d.getTime())));
                    const dur = Math.round((max - min) / (1000 * 60 * 60 * 24));
                    if (!etapaDurations[etapa]) etapaDurations[etapa] = [];
                    etapaDurations[etapa].push(dur);
                    perBpDurations[etapa] = dur;
                    allDurations.push(dur);
                });

                if (Object.keys(perBpDurations).length) {
                    bpEtapaDurations[curBp] = perBpDurations;
                }

            } catch (_) {
                continue;
            }
        }
    });

    await Promise.all(workers);

    const etapaRows = Object.entries(etapaDurations)
        .map(([etapa, durations]) => {
            const avg = durations.length ? durations.reduce((a, b) => a + b, 0) / durations.length : 0;
            return { etapa, avg_days: Math.round(avg * 100) / 100, count: durations.length };
        })
        .sort((a, b) => b.avg_days - a.avg_days);

    const areaRows = Object.entries(areaStats)
        .map(([area, data]) => ({ area, events: data.events, bps: data.bps.size }))
        .sort((a, b) => b.events - a.events);

    const empresaRows = Object.entries(empresaStats)
        .map(([empresa, data]) => ({ empresa, events: data.events, bps: data.bps.size }))
        .sort((a, b) => b.events - a.events);

    const totalHours = Object.values(bpHours).reduce((a, b) => a + b, 0);

    return {
        status: 'success',
        summary: {
            total_bps: totalBps,
            open_bps: openCount,
            closed_bps: closedCount,
            total_bp_hours: Math.round(totalHours * 100) / 100
        },
        open_by_etapa: openByEtapa,
        open_by_situacion: openBySituacion,
        status_counts: statusCounts,
        active_by_etapa: activeByEtapa,
        standby_by_etapa: standbyByEtapa,
        closed_by_situacion: closedBySituacion,
        active_bps: activeBps,
        standby_bps: standbyBps,
        closed_bps: closedBps,
        bp_etapa_days: bpEtapaDurations,
        gauss_days: allDurations,
        user_hours: userHoursRows,
        bp_hours: bpHoursRows,
        user_bp_hours: userBpRows,
        etapas: etapaRows,
        areas: areaRows,
        empresas: empresaRows,
        generated_at: new Date().toISOString().slice(0, 19).replace('T', ' ')
    };
}

function renderISOStats(data) {
    const summary = data.summary || {};
    const sections = document.getElementById('iso-stats-sections');
    if (!sections) return;
    sections.innerHTML = '';

    const meta = document.getElementById('iso-stats-meta');
    if (meta) meta.textContent = data.generated_at ? `Actualizado: ${data.generated_at}` : '';

    const statusCounts = data.status_counts || {};
    const activeCount = (typeof statusCounts.activo === 'number') ? statusCounts.activo : (summary.open_bps || 0);
    const standbyCount = (typeof statusCounts.standby === 'number') ? statusCounts.standby : 0;
    const closedCount = (typeof statusCounts.cerrado === 'number') ? statusCounts.cerrado : (summary.closed_bps || 0);
    const totalBps = summary.total_bps || (activeCount + standbyCount + closedCount);

    const activePct = totalBps ? Math.round((activeCount / totalBps) * 100) : 0;
    const standbyPct = totalBps ? Math.round((standbyCount / totalBps) * 100) : 0;
    const closedPct = totalBps ? Math.round((closedCount / totalBps) * 100) : 0;

    const activeByEtapa = objectToRows(data.active_by_etapa, 'Etapa');
    const standbyByEtapa = objectToRows(data.standby_by_etapa, 'Etapa');
    const closedBySituacion = objectToRows(data.closed_by_situacion, 'Resultado');

    const etapas = buildIsoNormalizedStageRows(Array.isArray(data.etapas) ? data.etapas : []);
    applyIsoStageModelFromRows(etapas);
    const userHours = Array.isArray(data.user_hours) ? data.user_hours.slice(0, 8) : [];
    const bpHours = Array.isArray(data.bp_hours) ? data.bp_hours.slice(0, 8) : [];

    const activeBps = Array.isArray(data.active_bps) ? data.active_bps.slice() : [];
    const bpEtapaDays = data.bp_etapa_days || {};
    const allDurations = Array.isArray(data.gauss_days) ? data.gauss_days : [];

    const activeListHtml = renderISOBarList(activeByEtapa, 'label', 'value', '')?.outerHTML || '';
    const standbyListHtml = renderISOBarList(standbyByEtapa, 'label', 'value', '')?.outerHTML || '';
    const closedListHtml = renderISOBarList(closedBySituacion, 'label', 'value', '')?.outerHTML || '';

    sections.innerHTML = `
        <div class="iso-stats-grid">
            <div class="iso-state-layout span-12">
                <div class="iso-card iso-state-card iso-state-tall">
                    <div class="iso-card-title">BPs Estado</div>
                    <div class="iso-state-vertical">
                        <canvas id="iso-state-donut" class="iso-donut"></canvas>
                        <div class="iso-state-legend">
                            <div class="iso-legend-item"><span class="iso-dot dot-active"></span> Activo: <strong>${activeCount}</strong></div>
                            <div class="iso-legend-item"><span class="iso-dot dot-standby"></span> Stand By: <strong>${standbyCount}</strong></div>
                            <div class="iso-legend-item"><span class="iso-dot dot-closed"></span> Cerrado: <strong>${closedCount}</strong></div>
                            <div class="iso-legend-sub">Total: ${totalBps}</div>
                        </div>
                    </div>
                </div>
                <div class="iso-state-stack">
                    <div class="iso-card iso-state-card">
                        <div class="iso-card-title">BPs Activos</div>
                        <div class="iso-state-body">
                            <div class="iso-state-ring">
                                <canvas id="iso-active-ring"></canvas>
                                <div class="iso-state-label">${activePct}%<span>${activeCount} activos</span></div>
                            </div>
                            <div class="iso-state-breakdown">${activeListHtml}</div>
                        </div>
                    </div>

                    <div class="iso-card iso-state-card">
                        <div class="iso-card-title">BPs Stand By</div>
                        <div class="iso-state-body">
                            <div class="iso-state-ring">
                                <canvas id="iso-standby-ring"></canvas>
                                <div class="iso-state-label">${standbyPct}%<span>${standbyCount} stand by</span></div>
                            </div>
                            <div class="iso-state-breakdown">${standbyListHtml}</div>
                        </div>
                    </div>

                    <div class="iso-card iso-state-card">
                        <div class="iso-card-title">BPs Cerrados</div>
                        <div class="iso-state-body">
                            <div class="iso-state-ring">
                                <canvas id="iso-closed-ring"></canvas>
                                <div class="iso-state-label">${closedPct}%<span>${closedCount} cerrados</span></div>
                            </div>
                            <div class="iso-state-breakdown">${closedListHtml}</div>
                        </div>
                    </div>
                </div>
            </div>

            <div class="iso-card span-12">
                <div class="iso-card-title">Tiempo por Etapa en BPs Activos</div>
                <div class="iso-stack-scroll">
                    <canvas id="iso-stack-bp" class="iso-chart iso-chart-wide" aria-label="Tiempo por etapa"></canvas>
                </div>
                <div id="iso-stack-legend" class="iso-stack-legend"></div>
            </div>

            <div class="iso-card span-6">
                <div class="iso-card-title">Promedio por Etapa (d&iacute;as)</div>
                ${renderISOStatsTable(etapas, [
        { key: 'etapa', label: 'Etapa' },
        { key: 'avg_days', label: 'Promedio (d)', align: 'right' },
        { key: 'count', label: 'Casos', align: 'right' }
    ])?.outerHTML || ''}
            </div>

            <div class="iso-card span-6">
                <div class="iso-card-title">Distribuci&oacute;n de Duraci&oacute;n (Gauss)</div>
                <canvas id="iso-gauss" class="iso-chart" aria-label="Distribucion"></canvas>
                <div id="iso-gauss-meta" class="iso-gauss-meta"></div>
            </div>

            <div class="iso-card span-6">
                <div class="iso-card-title">Horas por BP</div>
                <canvas id="iso-line-hours" class="iso-chart" aria-label="Horas por BP"></canvas>
            </div>

            <div class="iso-card span-6">
                <div class="iso-card-title">Horas por Usuario</div>
                <canvas id="iso-bar-users" class="iso-chart" aria-label="Horas por usuario"></canvas>
            </div>
        </div>
    `;

    const donutCanvas = document.getElementById('iso-state-donut');
    if (donutCanvas) {
        drawIsoDonut(donutCanvas, [
            { label: 'Activo', value: activeCount, color: '#3498db' },
            { label: 'Stand By', value: standbyCount, color: '#f1c40f' },
            { label: 'Cerrado', value: closedCount, color: '#2ecc71' }
        ]);
    }

    const activeRing = document.getElementById('iso-active-ring');
    if (activeRing) drawIsoRing(activeRing, activePct, '#3498db');

    const standbyRing = document.getElementById('iso-standby-ring');
    if (standbyRing) drawIsoRing(standbyRing, standbyPct, '#f1c40f');

    const closedRing = document.getElementById('iso-closed-ring');
    if (closedRing) drawIsoRing(closedRing, closedPct, '#2ecc71');

    const stageOrderSet = new Set();
    activeBps.forEach(bp => {
        const stages = bpEtapaDays[bp] || {};
        Object.keys(stages).forEach(et => stageOrderSet.add(et));
    });

    const etapaAvgMap = {};
    etapas.forEach(item => { etapaAvgMap[item.etapa] = item.avg_days; });

    const stageOrder = Array.from(stageOrderSet);
    stageOrder.sort((a, b) => (etapaAvgMap[b] || 0) - (etapaAvgMap[a] || 0));

    const palette = ['#4a90e2', '#f5a623', '#50e3c2', '#b8e986', '#bd10e0', '#f8e71c', '#7ed321', '#9013fe', '#d0021b', '#8b572a', '#417505', '#4a4a4a'];
    const stageColors = {};
    stageOrder.forEach((stage, idx) => { stageColors[stage] = palette[idx % palette.length]; });

    const sortedActive = activeBps.slice().sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
    const matrix = sortedActive.map(bp => stageOrder.map(stage => (bpEtapaDays[bp] && bpEtapaDays[bp][stage]) ? Number(bpEtapaDays[bp][stage]) : 0));

    const stackCanvas = document.getElementById('iso-stack-bp');
    if (stackCanvas) {
        if (!sortedActive.length || !stageOrder.length) {
            const wrap = stackCanvas.parentElement;
            if (wrap) wrap.innerHTML = '<div style="color:var(--text-secondary); padding:1rem;">Sin datos de etapas para BPs activos.</div>';
        } else {
            const minWidth = Math.max(800, sortedActive.length * 70);
            stackCanvas.style.width = `${minWidth}px`;
            stackCanvas.style.height = '320px';
            drawIsoStackedBar(stackCanvas, sortedActive, stageOrder, matrix, stageColors);
        }
    }

    const legend = document.getElementById('iso-stack-legend');
    if (legend && stageOrder.length) {
        legend.innerHTML = stageOrder.map(stage => `
            <span class="iso-legend-pill"><span class="iso-dot" style="background:${stageColors[stage]}"></span>${stage}</span>
        `).join('');
    }

    const gaussCanvas = document.getElementById('iso-gauss');
    if (gaussCanvas) {
        const stats = drawIsoGaussChart(gaussCanvas, allDurations);
        const metaEl = document.getElementById('iso-gauss-meta');
        if (metaEl) {
            if (stats) {
                metaEl.textContent = `Promedio: ${stats.mean} d - Desvio: ${stats.stdev} d`;
            } else {
                metaEl.textContent = 'Sin datos de duraciones.';
            }
        }
    }

    const lineCanvas = document.getElementById('iso-line-hours');
    if (lineCanvas) {
        drawIsoLineChart(lineCanvas, bpHours.map(b => b.hours), bpHours.map(b => b.bp));
    }

    const barUsers = document.getElementById('iso-bar-users');
    if (barUsers) {
        drawIsoBarChart(barUsers, userHours.map(u => u.hours), userHours.map(u => u.user));
    }

    requestAnimationFrame(syncIsoStateHeights);
    setTimeout(syncIsoStateHeights, 200);

    if (!window._isoStateResizeBound) {
        window.addEventListener('resize', () => {
            const view = document.getElementById('view-iso-stats');
            if (view && view.style.display !== 'none') {
                syncIsoStateHeights();
            }
        });
        window._isoStateResizeBound = true;
    }
}


function syncIsoStateHeights() {
    const layout = document.querySelector('#view-iso-stats .iso-state-layout');
    if (!layout) return;
    const left = layout.querySelector('.iso-state-tall');
    const stack = layout.querySelector('.iso-state-stack');
    if (!left || !stack) return;
    const leftRect = left.getBoundingClientRect();
    const stackRect = stack.getBoundingClientRect();
    const target = Math.max(0, stackRect.bottom - leftRect.top);
    if (target) {
        left.style.height = `${target}px`;
    }
}



function renderIsoStatsMonths() {
    const months = ['ENE', 'FEB', 'MAR', 'ABR', 'MAY', 'JUN', 'JUL', 'AGO', 'SEP', 'OCT', 'NOV', 'DIC'];
    const cont = document.getElementById('iso-stats-months');
    const lbl = document.getElementById('iso-stats-year-label');
    const rangeLbl = document.getElementById('iso-stats-range-label');
    if (lbl) lbl.textContent = isoStatsAllYears ? "Todos" : isoStatsYear;
    const allBtn = document.getElementById('iso-stats-all-years-btn');
    if (allBtn) {
        allBtn.style.background = isoStatsAllYears ? 'var(--bpb-blue)' : 'rgba(255,255,255,0.05)';
        allBtn.style.color = isoStatsAllYears ? '#fff' : 'var(--text-primary)';
        allBtn.style.borderColor = 'var(--border)';
    }
    if (cont) {
        cont.innerHTML = '';
        months.forEach((m, idx) => {
            const btn = document.createElement('button');
            btn.className = 'btn';
            btn.style.padding = '6px 8px';
            btn.style.borderColor = 'var(--border)';
            btn.style.background = 'rgba(255,255,255,0.05)';
            btn.style.color = 'var(--text-primary)';
            btn.textContent = m;
            let selected = false;
            if (isoStatsStartMonth !== null && isoStatsEndMonth === null && isoStatsStartMonth === idx) selected = true;
            if (isoStatsStartMonth !== null && isoStatsEndMonth !== null && idx >= isoStatsStartMonth && idx <= isoStatsEndMonth) selected = true;
            if (selected) {
                btn.style.background = 'var(--bpb-blue)';
                btn.style.color = '#fff';
            }
            btn.onclick = () => isoStatsSelectMonth(idx);
            if (isoStatsAllYears) {
                btn.disabled = true;
                btn.style.opacity = '0.5';
            }
            cont.appendChild(btn);
        });
    }
    if (rangeLbl) {
        if (isoStatsAllYears) {
            rangeLbl.textContent = 'Todos los a&ntilde;os';
        } else if (isoStatsStartMonth === null) {
            rangeLbl.textContent = 'Todos los meses';
        } else if (isoStatsEndMonth === null) {
            rangeLbl.textContent = `${months[isoStatsStartMonth]} ${isoStatsYear}`;
        } else {
            rangeLbl.textContent = `${months[isoStatsStartMonth]} - ${months[isoStatsEndMonth]} ${isoStatsYear}`;
        }
    }
}


function isoStatsAllYearsMode() {
    isoStatsAllYears = true;
    isoStatsStartMonth = null;
    isoStatsEndMonth = null;
    renderIsoStatsMonths();
    refreshISOStats();
}
function isoStatsPrevYear() {
    isoStatsAllYears = false;
    isoStatsYear -= 1;
    renderIsoStatsMonths();
    refreshISOStats();
}

function isoStatsNextYear() {
    isoStatsAllYears = false;
    isoStatsYear += 1;
    renderIsoStatsMonths();
    refreshISOStats();
}

function isoStatsSelectMonth(idx) {
    isoStatsAllYears = false;
    if (isoStatsStartMonth !== null && isoStatsEndMonth === null && isoStatsStartMonth === idx) {
        isoStatsStartMonth = null;
        isoStatsEndMonth = null;
    } else if (isoStatsStartMonth === null || (isoStatsStartMonth !== null && isoStatsEndMonth !== null)) {
        isoStatsStartMonth = idx;
        isoStatsEndMonth = null;
    } else {
        if (idx < isoStatsStartMonth) {
            isoStatsEndMonth = isoStatsStartMonth;
            isoStatsStartMonth = idx;
        } else {
            isoStatsEndMonth = idx;
        }
    }
    renderIsoStatsMonths();
    refreshISOStats();
}

function getIsoStatsDateRange() {
    let start = '';
    let end = '';
    if (isoStatsAllYears) {
        return { start: '', end: '' };
    }
    if (isoStatsStartMonth === null && isoStatsEndMonth === null) {
        start = new Date(isoStatsYear, 0, 1).toISOString().slice(0, 10);
        end = new Date(isoStatsYear, 11, 31).toISOString().slice(0, 10);
    } else if (isoStatsStartMonth !== null && isoStatsEndMonth === null) {
        const d0 = new Date(isoStatsYear, isoStatsStartMonth, 1);
        const d1 = new Date(isoStatsYear, isoStatsStartMonth + 1, 0);
        start = d0.toISOString().slice(0, 10);
        end = d1.toISOString().slice(0, 10);
    } else if (isoStatsStartMonth !== null && isoStatsEndMonth !== null) {
        const d0 = new Date(isoStatsYear, isoStatsStartMonth, 1);
        const d1 = new Date(isoStatsYear, isoStatsEndMonth + 1, 0);
        start = d0.toISOString().slice(0, 10);
        end = d1.toISOString().slice(0, 10);
    }
    return { start, end };
}

async function refreshISOStats() {
    const sections = document.getElementById('iso-stats-sections');
    if (sections) {
        sections.innerHTML = '<div class="iso-stats-loading"><div class="iso-spinner"></div><div>Cargando estadisticas ISO...</div></div>';
    }
    try {
        const data = await loadISOStatsData();
        if (!data || data.status !== 'success') {
            const msg = data && data.message ? data.message : 'No se pudieron obtener las estadisticas ISO.';
            if (typeof showNotification === 'function') showNotification(msg, 'error');
            if (sections) sections.innerHTML = `<div style="color:#e74c3c;">${msg}</div>`;
            return;
        }
        renderISOStats(data);
    } catch (err) {
        console.error('ISO stats fetch failed', err);
        if (sections) sections.innerHTML = '<div style="color:#e74c3c;">Error de conexion al cargar estadisticas ISO.</div>';
    }
}

function initIsoStatsFilters() {
    renderIsoStatsMonths();
}


function printISOStats() {
    const view = document.getElementById('view-iso-stats');
    if (!view) {
        window.print();
        return;
    }

    const body = document.body;
    const originalClass = body.className;
    body.classList.add('print-iso-only');

    window.print();

    setTimeout(() => {
        body.className = originalClass;
    }, 300);
}

function renderISOStatsTable(rows, columns) {
    const wrap = document.createElement('div');
    if (!rows || rows.length === 0) {
        wrap.innerHTML = '<div style="color:var(--text-secondary);">Sin datos</div>';
        return wrap;
    }
    const table = document.createElement('table');
    table.style.width = '100%';
    table.style.borderCollapse = 'collapse';

    const thead = document.createElement('thead');
    const trh = document.createElement('tr');
    columns.forEach(col => {
        const th = document.createElement('th');
        th.textContent = col.label;
        th.style.textAlign = col.align || 'left';
        th.style.fontSize = '0.75rem';
        th.style.textTransform = 'uppercase';
        th.style.letterSpacing = '0.08em';
        th.style.color = 'var(--text-secondary)';
        th.style.padding = '8px 6px';
        th.style.borderBottom = '1px solid var(--border)';
        trh.appendChild(th);
    });
    thead.appendChild(trh);
    table.appendChild(thead);

    const tbody = document.createElement('tbody');
    rows.forEach(row => {
        const tr = document.createElement('tr');
        columns.forEach(col => {
            const td = document.createElement('td');
            td.style.padding = '8px 6px';
            td.style.borderBottom = '1px solid rgba(255,255,255,0.05)';
            td.style.color = 'var(--text-primary)';
            td.style.fontSize = '0.9rem';
            td.style.textAlign = col.align || 'left';
            td.textContent = row[col.key] !== undefined ? row[col.key] : '';
            tr.appendChild(td);
        });
        tbody.appendChild(tr);
    });
    table.appendChild(tbody);
    wrap.appendChild(table);
    return wrap;
}

function objectToRows(obj, label) {
    const rows = [];
    if (!obj) return rows;
    Object.keys(obj).forEach(key => {
        rows.push({ label: key || label, value: obj[key] });
    });
    rows.sort((a, b) => (b.value || 0) - (a.value || 0));
    return rows;
}


function renderISOBarList(items, labelKey, valueKey, suffix) {
    const container = document.createElement('div');
    if (!items || items.length === 0) {
        container.innerHTML = '<div style="color:var(--text-secondary);">Sin datos</div>';
        return container;
    }

    const maxVal = Math.max(...items.map(i => Number(i[valueKey]) || 0), 0) || 1;

    items.forEach(item => {
        const row = document.createElement('div');
        row.style.display = 'grid';
        row.style.gridTemplateColumns = '1fr 4fr 80px';
        row.style.gap = '12px';
        row.style.alignItems = 'center';
        row.style.marginBottom = '8px';

        const label = document.createElement('div');
        label.style.color = 'var(--text-primary)';
        label.style.fontSize = '0.9rem';
        label.textContent = item[labelKey] || '-';

        const barWrap = document.createElement('div');
        barWrap.style.background = 'rgba(255,255,255,0.05)';
        barWrap.style.borderRadius = '8px';
        barWrap.style.height = '10px';
        barWrap.style.overflow = 'hidden';

        const bar = document.createElement('div');
        const rawVal = Number(item[valueKey]) || 0;
        const pct = Math.max(2, Math.round((rawVal / maxVal) * 100));
        bar.style.width = pct + '%';
        bar.style.height = '100%';
        bar.style.background = 'var(--bpb-blue)';
        barWrap.appendChild(bar);

        const value = document.createElement('div');
        value.style.textAlign = 'right';
        value.style.color = 'var(--text-secondary)';
        value.style.fontSize = '0.85rem';
        value.textContent = rawVal + (suffix ? ` ${suffix}` : '');

        row.appendChild(label);
        row.appendChild(barWrap);
        row.appendChild(value);
        container.appendChild(row);
    });

    return container;
}

function renderISOBaRList(items, labelKey, valueKey, suffix) {
    return renderISOBarList(items, labelKey, valueKey, suffix);
}



function isoSetupCanvas(canvas) {
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    const width = rect.width || 300;
    const height = rect.height || 200;
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = width + 'px';
    canvas.style.height = height + 'px';
    const ctx = canvas.getContext('2d');
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    return { ctx, width, height };
}

function drawIsoLineChart(canvas, values, labels) {
    const { ctx, width, height } = isoSetupCanvas(canvas);
    ctx.clearRect(0, 0, width, height);
    if (!values || values.length === 0) {
        ctx.fillStyle = '#777';
        ctx.font = '12px "Manrope", sans-serif';
        ctx.fillText('Sin datos', 20, 30);
        return;
    }
    const padding = { left: 40, right: 20, top: 16, bottom: 28 };
    const w = width - padding.left - padding.right;
    const h = height - padding.top - padding.bottom;
    const maxVal = Math.max(...values, 1);
    const stepX = w / Math.max(values.length - 1, 1);

    ctx.strokeStyle = 'rgba(255,255,255,0.08)';
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
        const y = padding.top + (h / 4) * i;
        ctx.beginPath();
        ctx.moveTo(padding.left, y);
        ctx.lineTo(padding.left + w, y);
        ctx.stroke();
    }

    ctx.beginPath();
    values.forEach((val, idx) => {
        const x = padding.left + idx * stepX;
        const y = padding.top + h - (val / maxVal) * h;
        if (idx === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
    });
    ctx.strokeStyle = '#4aa3ff';
    ctx.lineWidth = 2;
    ctx.stroke();

    ctx.lineTo(padding.left + w, padding.top + h);
    ctx.lineTo(padding.left, padding.top + h);
    ctx.closePath();
    const grad = ctx.createLinearGradient(0, padding.top, 0, padding.top + h);
    grad.addColorStop(0, 'rgba(74,163,255,0.28)');
    grad.addColorStop(1, 'rgba(74,163,255,0.05)');
    ctx.fillStyle = grad;
    ctx.fill();

    ctx.fillStyle = '#cfd2d6';
    ctx.font = '10px "Manrope", sans-serif';
    ctx.textAlign = 'center';
    const labelStep = values.length > 6 ? 2 : 1;
    labels.forEach((lab, idx) => {
        if (idx % labelStep !== 0) return;
        const x = padding.left + idx * stepX;
        ctx.fillText(lab, x, padding.top + h + 18);
    });
}

function drawIsoDonut(canvas, segments) {
    const { ctx, width, height } = isoSetupCanvas(canvas);
    ctx.clearRect(0, 0, width, height);
    const total = segments.reduce((a, b) => a + (b.value || 0), 0);
    if (total <= 0) {
        ctx.fillStyle = '#777';
        ctx.font = '12px "Manrope", sans-serif';
        ctx.fillText('Sin datos', 20, 30);
        return;
    }
    const cx = width / 2;
    const cy = height / 2;
    const radius = Math.min(width, height) / 2 - 8;
    const inner = radius * 0.6;
    let start = -Math.PI / 2;
    segments.forEach(seg => {
        const slice = (seg.value / total) * Math.PI * 2;
        ctx.beginPath();
        ctx.arc(cx, cy, radius, start, start + slice);
        ctx.arc(cx, cy, inner, start + slice, start, true);
        ctx.closePath();
        ctx.fillStyle = seg.color || '#4aa3ff';
        ctx.fill();
        start += slice;
    });
}

function drawIsoRing(canvas, percent, color) {
    const { ctx, width, height } = isoSetupCanvas(canvas);
    ctx.clearRect(0, 0, width, height);
    const cx = width / 2;
    const cy = height / 2;
    const radius = Math.min(width, height) / 2 - 6;
    const thickness = radius * 0.25;
    ctx.lineWidth = thickness;
    ctx.strokeStyle = 'rgba(255,255,255,0.1)';
    ctx.beginPath();
    ctx.arc(cx, cy, radius, 0, Math.PI * 2);
    ctx.stroke();

    const end = (Math.PI * 2) * (Math.max(0, Math.min(100, percent)) / 100);
    ctx.strokeStyle = color || '#4aa3ff';
    ctx.beginPath();
    ctx.arc(cx, cy, radius, -Math.PI / 2, -Math.PI / 2 + end);
    ctx.stroke();
}

function drawIsoBarChart(canvas, values, labels) {
    const { ctx, width, height } = isoSetupCanvas(canvas);
    ctx.clearRect(0, 0, width, height);
    if (!values || values.length === 0) {
        ctx.fillStyle = '#777';
        ctx.font = '12px "Manrope", sans-serif';
        ctx.fillText('Sin datos', 20, 30);
        return;
    }
    const padding = { left: 40, right: 16, top: 16, bottom: 28 };
    const w = width - padding.left - padding.right;
    const h = height - padding.top - padding.bottom;
    const maxVal = Math.max(...values, 1);
    const barGap = 8;
    const barWidth = (w - barGap * (values.length - 1)) / values.length;

    values.forEach((val, idx) => {
        const x = padding.left + idx * (barWidth + barGap);
        const barH = (val / maxVal) * h;
        const y = padding.top + h - barH;
        ctx.fillStyle = 'rgba(74,163,255,0.85)';
        ctx.fillRect(x, y, barWidth, barH);
    });

    ctx.fillStyle = '#cfd2d6';
    ctx.font = '10px "Manrope", sans-serif';
    ctx.textAlign = 'center';
    labels.forEach((lab, idx) => {
        const x = padding.left + idx * (barWidth + barGap) + barWidth / 2;
        ctx.fillText(lab, x, padding.top + h + 18);
    });
}

function drawIsoRadarChart(canvas, values, labels) {
    const { ctx, width, height } = isoSetupCanvas(canvas);
    ctx.clearRect(0, 0, width, height);
    if (!values || values.length === 0) {
        ctx.fillStyle = '#777';
        ctx.font = '12px "Manrope", sans-serif';
        ctx.fillText('Sin datos', 20, 30);
        return;
    }
    const cx = width / 2;
    const cy = height / 2;
    const radius = Math.min(width, height) * 0.35;
    const maxVal = Math.max(...values, 1);
    const steps = 4;

    ctx.strokeStyle = 'rgba(255,255,255,0.08)';
    for (let s = 1; s <= steps; s++) {
        ctx.beginPath();
        const r = (radius / steps) * s;
        values.forEach((_, idx) => {
            const angle = (Math.PI * 2 * idx) / values.length - Math.PI / 2;
            const x = cx + Math.cos(angle) * r;
            const y = cy + Math.sin(angle) * r;
            if (idx === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
        });
        ctx.closePath();
        ctx.stroke();
    }

    ctx.beginPath();
    values.forEach((val, idx) => {
        const angle = (Math.PI * 2 * idx) / values.length - Math.PI / 2;
        const r = (val / maxVal) * radius;
        const x = cx + Math.cos(angle) * r;
        const y = cy + Math.sin(angle) * r;
        if (idx === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
    });
    ctx.closePath();
    ctx.fillStyle = 'rgba(155, 89, 182, 0.35)';
    ctx.strokeStyle = 'rgba(155, 89, 182, 0.9)';
    ctx.lineWidth = 2;
    ctx.fill();
    ctx.stroke();

    ctx.fillStyle = '#cfd2d6';
    ctx.font = '10px "Manrope", sans-serif';
    ctx.textAlign = 'center';
    labels.forEach((lab, idx) => {
        const angle = (Math.PI * 2 * idx) / labels.length - Math.PI / 2;
        const x = cx + Math.cos(angle) * (radius + 14);
        const y = cy + Math.sin(angle) * (radius + 14);
        ctx.fillText(lab, x, y);
    });
}


function drawIsoStackedBar(canvas, labels, stages, matrix, colors) {
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    if (!labels || labels.length === 0 || !stages || stages.length === 0) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        ctx.font = '14px sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('Sin datos', (canvas.width || 300) / 2, (canvas.height || 200) / 2);
        return;
    }

    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    const width = rect.width || 800;
    const height = rect.height || 320;
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    ctx.scale(dpr, dpr);

    const padding = { left: 50, right: 20, top: 20, bottom: 50 };
    const chartW = width - padding.left - padding.right;
    const chartH = height - padding.top - padding.bottom;

    const totals = labels.map((_, i) => (matrix[i] || []).reduce((a, b) => a + (Number(b) || 0), 0));
    const maxVal = Math.max(...totals, 1);

    ctx.clearRect(0, 0, width, height);

    // Grid lines
    ctx.strokeStyle = 'rgba(255,255,255,0.08)';
    ctx.lineWidth = 1;
    const gridLines = 4;
    for (let i = 0; i <= gridLines; i++) {
        const y = padding.top + chartH - (chartH * i / gridLines);
        ctx.beginPath();
        ctx.moveTo(padding.left, y);
        ctx.lineTo(padding.left + chartW, y);
        ctx.stroke();

        const val = Math.round(maxVal * i / gridLines);
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        ctx.font = '10px sans-serif';
        ctx.textAlign = 'right';
        ctx.textBaseline = 'middle';
        ctx.fillText(val, padding.left - 6, y);
    }

    const barSpace = chartW / labels.length;
    const barWidth = Math.max(16, Math.min(42, barSpace * 0.7));
    const barOffset = (barSpace - barWidth) / 2;

    labels.forEach((label, i) => {
        const x = padding.left + i * barSpace + barOffset;
        let yBase = padding.top + chartH;

        stages.forEach((stage, sIdx) => {
            const val = (matrix[i] && matrix[i][sIdx]) ? Number(matrix[i][sIdx]) : 0;
            if (!val) return;
            const h = (val / maxVal) * chartH;
            const color = colors && colors[stage] ? colors[stage] : '#3498db';
            ctx.fillStyle = color;
            ctx.fillRect(x, yBase - h, barWidth, h);

            if (h >= 14) {
                ctx.fillStyle = 'rgba(255,255,255,0.9)';
                ctx.font = '10px sans-serif';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'bottom';
                ctx.fillText(`${val}d`, x + barWidth / 2, yBase - h + 12);
            }
            yBase -= h;
        });

        ctx.fillStyle = 'rgba(255,255,255,0.7)';
        ctx.font = '10px sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';

        const labelX = x + barWidth / 2;
        const labelY = padding.top + chartH + 6;
        const shouldRotate = barSpace < 60 || (label && label.length > 8);
        if (shouldRotate) {
            ctx.save();
            ctx.translate(labelX, labelY + 6);
            ctx.rotate(-0.4);
            ctx.fillText(label, 0, 0);
            ctx.restore();
        } else {
            ctx.fillText(label, labelX, labelY);
        }
    });
}

function drawIsoGaussChart(canvas, values) {
    if (!canvas) return null;
    const ctx = canvas.getContext('2d');
    if (!ctx) return null;

    const data = (values || []).map(v => Number(v)).filter(v => Number.isFinite(v));
    const rect = canvas.getBoundingClientRect();
    const width = rect.width || 400;
    const height = rect.height || 240;
    const dpr = window.devicePixelRatio || 1;
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    ctx.scale(dpr, dpr);

    ctx.clearRect(0, 0, width, height);

    if (!data.length) {
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        ctx.font = '14px sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('Sin datos', width / 2, height / 2);
        return null;
    }

    const mean = data.reduce((a, b) => a + b, 0) / data.length;
    const variance = data.reduce((acc, v) => acc + Math.pow(v - mean, 2), 0) / data.length;
    const stdev = Math.sqrt(variance) || 1;
    const min = Math.min(...data);
    const max = Math.max(...data);

    const bins = Math.max(6, Math.min(12, Math.round(Math.sqrt(data.length))));
    const binSize = (max - min) / bins || 1;
    const counts = new Array(bins).fill(0);

    data.forEach(v => {
        const idx = Math.min(bins - 1, Math.floor((v - min) / binSize));
        counts[idx] += 1;
    });

    const maxCount = Math.max(...counts, 1);
    const padding = { left: 40, right: 20, top: 20, bottom: 40 };
    const chartW = width - padding.left - padding.right;
    const chartH = height - padding.top - padding.bottom;

    ctx.strokeStyle = 'rgba(255,255,255,0.08)';
    ctx.lineWidth = 1;
    const gridLines = 4;
    for (let i = 0; i <= gridLines; i++) {
        const y = padding.top + chartH - (chartH * i / gridLines);
        ctx.beginPath();
        ctx.moveTo(padding.left, y);
        ctx.lineTo(padding.left + chartW, y);
        ctx.stroke();
    }

    const barW = chartW / bins;
    counts.forEach((c, i) => {
        const h = (c / maxCount) * chartH;
        const x = padding.left + i * barW;
        const y = padding.top + chartH - h;
        ctx.fillStyle = 'rgba(52,152,219,0.45)';
        ctx.fillRect(x + 4, y, barW - 8, h);
    });

    // Gaussian curve
    const gauss = (x) => (1 / (stdev * Math.sqrt(2 * Math.PI))) * Math.exp(-0.5 * Math.pow((x - mean) / stdev, 2));
    const peak = gauss(mean);
    const scale = maxCount / peak;

    ctx.beginPath();
    const steps = 80;
    for (let i = 0; i <= steps; i++) {
        const xVal = min + (max - min) * (i / steps);
        const yVal = gauss(xVal) * scale;
        const x = padding.left + ((xVal - min) / (max - min || 1)) * chartW;
        const y = padding.top + chartH - (yVal / maxCount) * chartH;
        if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
    }
    ctx.strokeStyle = '#f5a623';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Mean line
    const meanX = padding.left + ((mean - min) / (max - min || 1)) * chartW;
    ctx.strokeStyle = 'rgba(255,255,255,0.4)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(meanX, padding.top);
    ctx.lineTo(meanX, padding.top + chartH);
    ctx.stroke();

    return { mean: Math.round(mean * 100) / 100, stdev: Math.round(stdev * 100) / 100 };
}
async function loadAdminUsers() {
    const tbody = document.querySelector('#users-table tbody');
    if (!tbody) return;

    tbody.innerHTML = '<tr><td colspan="5" class="text-center">Cargando...</td></tr>';

    try {
        const response = await fetch('/api/admin/users');
        const users = await response.json();

        if (users.status === 'error') {
            tbody.innerHTML = `<tr><td colspan="5" class="text-center" style="color:var(--bpb-blue)">${users.message}</td></tr>`;
            return;
        }

        adminUsersCache = users; // Cache for search
        renderUsers(users);
    } catch (e) {
        tbody.innerHTML = `<tr><td colspan="5" class="text-center">Error loading users</td></tr>`;
    }
}

function renderUsers(users) {

    const tbody = document.querySelector('#users-table tbody');

    tbody.innerHTML = '';

    if (users.length === 0) {

        tbody.innerHTML = `<tr><td colspan="5" class="text-center">No users found</td></tr>`;

        return;

    }

    users.forEach(u => {

        const tr = document.createElement('tr');

        // Role Select

        // Role Select

        const roleSelect = `

            <select class="role-select" onchange="updateUserRole('${u.username}', this.value)">

                <option value="user" ${u.role === 'user' ? 'selected' : ''}>O. Tecnica</option>

                <option value="admin" ${u.role === 'admin' ? 'selected' : ''}>Admin</option>

                <option value="calidad" ${u.role === 'calidad' ? 'selected' : ''}>Calidad</option>

                <option value="externos" ${u.role === 'externos' ? 'selected' : ''}>Externos</option>

            </select>

        `;

        // Actions

        let actionButtons = '';

        if (u.status !== 'approved') {

            actionButtons += `

                <button class="btn btn-sm" style="padding: 4px 8px; font-size: 0.8rem; margin-right: 5px; color: var(--success); border-color: var(--success);" onclick="confirmAction('approve', '${u.username}')">Aprobar</button>

            `;

        }

        // History Button (Only for approved users)

        if (u.status === 'approved') {

            actionButtons += `

                <button class="btn btn-sm" style="padding: 4px 8px; font-size: 0.8rem; margin-right: 5px; color: var(--text-secondary); border-color: var(--text-secondary);" onclick="viewUserHistory('${u.username}')">Historial</button>

            `;

        }

        // Delete/Reject Button (Always available to remove access)

        // Delete/Reject Button (Always available to remove access)

        actionButtons += `

            <button class="btn btn-sm" style="padding: 4px 8px; font-size: 0.8rem; color: #ff6b6b; border-color: #ff6b6b;" onclick="confirmAction('delete', '${u.username}')">X</button>

        `;

        // Status Badge

        // Status Badge

        const statusBadge = `<span class="status-badge ${u.status}">${u.status}</span>`;

        // Profile Pic

        const imgSrc = u.profile_pic ? `/api/profile/photo/${u.profile_pic}` : '/static/assets/iso_red.png';

        const imgHtml = `

            <div style="width: 40px; height: 40px; border-radius: 50%; overflow: hidden; cursor: pointer; border: 2px solid transparent; background: white; display: flex; align-items: center; justify-content: center;" 

                 onmouseover="this.style.borderColor='var(--bpb-blue)'" 

                 onmouseout="this.style.borderColor='transparent'"

                 onclick="triggerAdminUpload('${u.username}')"

                 title="Click para cambiar foto">

                <img src="${imgSrc}" style="width: 100%; height: 100%; object-fit: contain;">

            </div>

        `;

        tr.innerHTML = `

            <td>${imgHtml}</td>

            <td>${u.username}</td>

            <td>${roleSelect}</td>

            <td>${statusBadge}</td>

            <td>${u.created_at}</td>

            <td>${actionButtons}</td>

        `;

        tbody.appendChild(tr);

    });

}

async function viewUserHistory(username) {

    showNotification('Cargando historial...', 'info');

    try {

        const response = await fetch(`/api/admin/history/${username}`);

        const logs = await response.json();

        if (logs.status === 'error') {

            showNotification(logs.message, 'error');

            return;

        }

        renderHistoryModal(logs, username);

    } catch (e) {

        showNotification('Error cargando historial', 'error');

    }

}

function renderHistoryModal(logs, username) {

    const modalId = 'history-modal';

    let existing = document.getElementById(modalId);

    if (existing) existing.remove();

    // Formatting timestamp if needed, but python sends formatted string

    const rows = logs.length ? logs.map(log => {

        // Date Format logic

        let dateStr = log.timestamp || '-';

        try {

            const [dPart, tPart] = dateStr.split(' ');

            const [y, m, d] = dPart.split('-');

            const [hh, mm] = tPart.split(':');

            dateStr = `<div style="display:flex; flex-direction:column; align-items: center;">

                    <span style="font-weight:600; color:var(--text-primary);">${d}/${m}/${y}</span>

                    <span style="font-size:0.85rem; color:var(--text-secondary);">${hh}:${mm}</span>

                </div>`;

        } catch (e) { }

        // Badge Logic

        let actionText = log.action;

        let badgeColor = '#95a5a6';

        let badgeBg = 'rgba(149, 165, 166, 0.15)';

        const act = log.action.toUpperCase();

        if (act.includes('APPROVED PO') || act.includes('APPROVED USER') || act.includes('MANUAL REGISTER')) {

            actionText = 'Aprobado';

            if (act.includes('MANUAL REGISTER')) actionText = 'Reg. Manual';

            badgeColor = '#2ecc71';

            badgeBg = 'rgba(46, 204, 113, 0.15)';

        } else if (act.includes('UPDATED PO PROGRESS')) {

            actionText = 'Progreso PO';

            badgeColor = '#3498db';

            badgeBg = 'rgba(52, 152, 219, 0.15)';

        } else if (act.includes('REVERSED')) {

            actionText = 'Revertido';

            badgeColor = '#e67e22';

            badgeBg = 'rgba(230, 126, 34, 0.15)';

        } else if (act.includes('CSV') || act.includes('EDIT')) {

            actionText = 'Editado';

            badgeColor = '#9b59b6';

            badgeBg = 'rgba(155, 89, 182, 0.15)';

        } else if (act.includes('UPLOAD')) {

            actionText = 'Subida';

            badgeColor = '#1abc9c';

            badgeBg = 'rgba(26, 188, 156, 0.15)';

        } else if (act.includes('ROLE')) {

            actionText = 'Rol Editado';

            badgeColor = '#f1c40f';

            badgeBg = 'rgba(241, 196, 15, 0.15)';

        }

        return `

        <tr>

            <td style="padding: 10px; border-bottom: 1px solid #333; vertical-align: middle; text-align: center;">${dateStr}</td>

            <td style="padding: 10px; border-bottom: 1px solid #333; vertical-align: middle; text-align: center;">

                 <span style="

                        display: inline-block;

                        padding: 4px 10px;

                        border-radius: 12px;

                        font-size: 0.75rem;

                        font-weight: 600;

                        text-transform: uppercase;

                        letter-spacing: 0.5px;

                        color: ${badgeColor};

                        background: ${badgeBg};

                        border: 1px solid ${badgeColor}40;

                        white-space: nowrap;

                    ">${actionText}</span>

            </td>

            <td style="padding: 10px; border-bottom: 1px solid #333; color: #ccc; font-size: 0.9rem; vertical-align: middle;">${log.details}</td>

        </tr>`;

    }).join('') : '<tr><td colspan="3" class="text-center" style="padding:20px; color: #aaa;">Sin actividad registrada</td></tr>';

    const modal = document.createElement('div');

    modal.id = modalId;

    modal.className = 'modal-overlay';

    modal.style.display = 'flex'; // Force flex for centering

    modal.innerHTML = `

        <div class="modal-confirm-wrapper" style="max-width: 800px; width: 90%; background: #1e1e1e; border: 1px solid #333;">

            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom: 1rem; border-bottom: 1px solid #333; padding-bottom: 1rem;">

                <h3 style="margin:0; font-size: 1.2rem; color: #fff;">Historial de Actividad: <span style="color: var(--bpb-blue);">${username}</span></h3>

                <span style="cursor:pointer; font-size: 1.5rem; color: #888; transition: 0.2s;" onclick="document.getElementById('${modalId}').remove()" onmouseover="this.style.color='#fff'" onmouseout="this.style.color='#888'">&times;</span>

            </div>

            

            <div style="max-height: 500px; overflow-y: auto; background: #141414; border-radius: 6px; border: 1px solid #333; position: relative;">

                <table style="width: 100%; text-align: left; border-collapse: collapse;">

                    <thead>

                        <tr style="background: #252525;">

                            <th style="position: sticky; top: 0; background: #252525; padding: 12px 10px; border-bottom: 1px solid #444; color: #888; font-weight: 600; width: 15%; text-align: center; z-index: 10;">Fecha</th>

                            <th style="position: sticky; top: 0; background: #252525; padding: 12px 10px; border-bottom: 1px solid #444; color: #888; font-weight: 600; width: 20%; text-align: center; z-index: 10;">Acción</th>

                            <th style="position: sticky; top: 0; background: #252525; padding: 12px 10px; border-bottom: 1px solid #444; color: #888; font-weight: 600; z-index: 10;">Detalles</th>

                        </tr>

                    </thead>

                    <tbody>

                        ${rows}

                    </tbody>

                </table>

            </div>

             <div style="text-align: right; margin-top: 1rem;">

                 <button class="btn" style="background: var(--bpb-blue); color:white;" onclick="document.getElementById('${modalId}').remove()">Cerrar</button>

            </div>

        </div>

    `;

    document.body.appendChild(modal);

}

// Custom Modal Confirmation

function confirmAction(type, username) {

    // Create Modal HTML

    const modalId = 'confirm-modal';

    let existing = document.getElementById(modalId);

    if (existing) existing.remove();

    const msg = type === 'approve' ? `¿Aprobar acceso para <b>${username}</b>?` : `¿Eliminar / Rechazar usuario <b>${username}</b>?`;

    const actionFn = type === 'approve' ? `approveUser('${username}')` : `deleteUser('${username}')`;

    const btnClass = type === 'approve' ? 'btn-primary' : 'btn';

    const btnText = type === 'approve' ? 'Aprobar' : 'Eliminar';

    // Using appended CSS for .modal-overlay, .modal-confirm-wrapper

    const modal = document.createElement('div');

    modal.id = modalId;

    modal.className = 'modal-overlay';

    modal.innerHTML = `

        <div class="modal-confirm-wrapper">

            <h3 style="margin-bottom: 1rem;">Confirmación</h3>

            <p>${msg}</p>

            <div class="modal-actions">

                <button class="btn" onclick="document.getElementById('${modalId}').remove()">Cancelar</button>

                <button class="${btnClass} btn" onclick="${actionFn}; document.getElementById('${modalId}').remove()">${btnText}</button>

            </div>

        </div>

    `;

    document.body.appendChild(modal);

}

async function approveUser(username) {

    try {

        const response = await fetch('/api/admin/approve', {

            method: 'POST',

            headers: { 'Content-Type': 'application/json' },

            body: JSON.stringify({ username })

        });

        const res = await response.json();

        if (res.status === 'success') {

            showNotification('Usuario aprobado', 'success');

            showAdminUsers(); // Refresh

        } else {

            showNotification(res.message, 'error');

        }

    } catch (e) {

        showNotification('Error de conexión', 'error');

    }

}

