function getCotizacionCategoryConfig(key) {
    return COTIZACION_CATEGORY_CONFIG.find((item) => item.key === key) || COTIZACION_CATEGORY_CONFIG[COTIZACION_CATEGORY_CONFIG.length - 1];
}

function getCotizacionSubconceptOptions(categoryKey) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    const map = window._cotizacionSubconceptOptionsMap || {};
    const options = map[safeCategory];
    return Array.isArray(options) ? options : [];
}

function getCotizacionSubconceptOptionsWithManualLabor(categoryKey) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    const baseOptions = [...getCotizacionSubconceptOptions(safeCategory)];
    if (!COTIZACION_SUBCONCEPTO_AUTO_HORA_CATEGORIES.has(safeCategory)) {
        return baseOptions;
    }

    const manualLower = COTIZACION_SUBCONCEPTO_MANO_OBRA_LABEL.toLowerCase();
    const filtered = baseOptions.filter((item) => String(item?.subconcepto || '').trim().toLowerCase() !== manualLower);
    filtered.push({
        subconcepto: COTIZACION_SUBCONCEPTO_MANO_OBRA_LABEL,
        rate: COTIZACION_SUBCONCEPTO_MANO_OBRA_RATE
    });
    return filtered;
}

function categoryUsesCotizacionSubconceptIndex(categoryKey) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    return COTIZACION_SUBCONCEPTO_INDEX_CATEGORIES.has(safeCategory) && getCotizacionSubconceptOptionsWithManualLabor(safeCategory).length > 0;
}

function buildCotizacionSingleSelectHTML(config = {}) {
    const controlClass = String(config.controlClass || '').trim();
    const wrapperClass = String(config.wrapperClass || '').trim();
    const currentValue = String(config.currentValue || '').trim();
    const placeholderText = String(config.placeholderText || 'Seleccionar...').trim() || 'Seleccionar...';
    const options = Array.isArray(config.options) ? config.options : [];
    const currentLower = currentValue.toLowerCase();
    let hasCurrent = false;
    let selectedLabel = '';
    let selectedRate = '';
    let optionButtonsHTML = '';

    if (placeholderText) {
        const isSelected = !currentValue;
        if (isSelected) {
            selectedLabel = placeholderText;
        }
        optionButtonsHTML += `<button type="button" class="cot-single-select-option cot-single-select-option-placeholder${isSelected ? ' is-selected' : ''}" data-value="">${escapeCotizacionHTML(placeholderText)}</button>`;
    }

    optionButtonsHTML += options.map((item) => {
        const value = String(item?.value ?? '').trim();
        const label = String(item?.label ?? value).trim();
        if (!value) return '';
        const isSelected = !!currentValue && value.toLowerCase() === currentLower;
        if (isSelected) {
            hasCurrent = true;
            selectedLabel = label;
            selectedRate = String(item?.rate ?? '').trim();
        }

        const rateValue = String(item?.rate ?? '').trim();
        const rateAttr = rateValue ? ` data-rate="${escapeCotizacionHTML(rateValue)}"` : '';
        return `<button type="button" class="cot-single-select-option${isSelected ? ' is-selected' : ''}" data-value="${escapeCotizacionHTML(value)}"${rateAttr}>${escapeCotizacionHTML(label)}</button>`;
    }).join('');

    if (currentValue && !hasCurrent) {
        selectedLabel = currentValue;
    }

    const triggerLabel = selectedLabel || placeholderText;
    const safeWrapperClass = wrapperClass ? ` ${wrapperClass}` : '';
    const safeControlClass = controlClass ? ` ${controlClass}` : '';
    const selectedRateAttr = selectedRate ? ` data-selected-rate="${escapeCotizacionHTML(selectedRate)}"` : '';

    return `
        <div class="cot-single-select${safeWrapperClass}" data-placeholder="${escapeCotizacionHTML(placeholderText)}">
            <input type="hidden" class="cot-input cot-single-select-value${safeControlClass}" value="${escapeCotizacionHTML(currentValue)}"${selectedRateAttr}>
            <button type="button" class="cot-input cot-single-select-trigger${currentValue ? '' : ' is-placeholder'}">${escapeCotizacionHTML(triggerLabel)}</button>
            <div class="cot-single-select-menu" style="display:none;">
                ${optionButtonsHTML || `<div class="cot-single-select-empty">${escapeCotizacionHTML(placeholderText)}</div>`}
            </div>
        </div>
    `;
}

function buildCotizacionStaticSubconceptSelectHTML(options = [], currentValue = '', placeholderText = '') {
    const normalizedCurrent = String(currentValue || '').trim();
    const singleOptions = options
        .map((name) => String(name || '').trim())
        .filter(Boolean)
        .map((name) => ({ value: name, label: name }));

    if (normalizedCurrent && !singleOptions.some((item) => item.value.toLowerCase() === normalizedCurrent.toLowerCase())) {
        singleOptions.push({ value: normalizedCurrent, label: normalizedCurrent });
    }

    return buildCotizacionSingleSelectHTML({
        controlClass: 'cot-subconcepto',
        wrapperClass: 'cot-subconcepto-select-wrap',
        currentValue: normalizedCurrent,
        placeholderText: placeholderText || 'Seleccionar...',
        options: singleOptions
    });
}

function buildCotizacionSubconceptFieldHTML(categoryKey, currentValue = '') {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    const current = String(currentValue || '').trim();

    if (COTIZACION_SUBCONCEPTO_FIXED_DASH_CATEGORIES.has(safeCategory)) {
        return '<input type="text" class="cot-input cot-subconcepto cot-subconcepto-fixed" value="-" readonly>';
    }

    if (safeCategory === 'externos') {
        const options = [...COTIZACION_SUBCONCEPTO_EXTERNOS_OPTIONS];
        const normalizedCurrent = current === '-' ? '' : current;
        return buildCotizacionStaticSubconceptSelectHTML(options, normalizedCurrent, 'Seleccionar...');
    }

    if (!categoryUsesCotizacionSubconceptIndex(safeCategory)) {
        return `<textarea rows="1" class="cot-input cot-subconcepto cot-autogrow">${escapeCotizacionHTML(current)}</textarea>`;
    }

    const options = getCotizacionSubconceptOptionsWithManualLabor(safeCategory);
    const singleOptions = options
        .map((item) => {
            const name = String(item?.subconcepto || '').trim();
            if (!name) return null;
            const rateRaw = item?.rate;
            const rateNumber = Number(rateRaw);
            return {
                value: name,
                label: name,
                rate: Number.isFinite(rateNumber) ? String(rateNumber) : ''
            };
        })
        .filter(Boolean);

    if (current && !singleOptions.some((item) => item.value.toLowerCase() === current.toLowerCase())) {
        singleOptions.push({ value: current, label: current });
    }

    return buildCotizacionSingleSelectHTML({
        controlClass: 'cot-subconcepto',
        wrapperClass: 'cot-subconcepto-select-wrap',
        currentValue: current,
        placeholderText: 'Seleccionar...',
        options: singleOptions
    });
}

function syncCotizacionRateFromSubconceptRow(row, onlyIfEmptyRate = false) {
    if (!(row instanceof HTMLTableRowElement)) return;

    const select = row.querySelector('.cot-subconcepto');
    if (!(select instanceof HTMLInputElement || select instanceof HTMLSelectElement)) return;

    const rateInput = row.querySelector('.cot-rate');
    if (!(rateInput instanceof HTMLInputElement)) return;

    const hasRateValue = !!String(rateInput.value || '').trim();

    const selectedValue = String(select.value || '').trim();
    syncCotizacionIndiceFromSubconceptRow(row);
    if (onlyIfEmptyRate && hasRateValue) return;

    const rateRaw = String(select.dataset.selectedRate || '').trim();
    if (!rateRaw) {
        if (!onlyIfEmptyRate) {
            rateInput.dataset.formula = '';
            rateInput.value = '';
            updateCotizacionRowUnitPlaceholders(row);
        }
        return;
    }

    const rateNumber = parseFloat(rateRaw.replace(',', '.'));
    if (!Number.isFinite(rateNumber)) return;

    const category = sanitizeCotizacionCategory(row.dataset.category || 'extras');
    const indiceControl = row.querySelector('.cot-indice');
    let targetIndice = normalizeCotizacionIndiceFromComplementarioUnit(indiceControl?.value || '');
    if (isCotizacionTimeIndiceCategory(category)) {
        if (!targetIndice) {
            targetIndice = 'Horas';
            if (indiceControl instanceof HTMLInputElement || indiceControl instanceof HTMLSelectElement) {
                setCotizacionSingleSelectValue(indiceControl, targetIndice, { dispatchEvents: false });
            }
        }
        row.dataset.lastIndice = targetIndice;
    }

    const targetFactor = isCotizacionTimeIndiceCategory(category)
        ? getCotizacionIndiceConversionFactor(targetIndice || 'Horas')
        : 1;
    const convertedRate = rateNumber * targetFactor;

    rateInput.dataset.formula = '';
    setCotizacionNumericDisplayValue(rateInput, convertedRate);
    updateCotizacionRowUnitPlaceholders(row);
}

function syncCotizacionIndiceFromSubconceptRow(row) {
    if (!(row instanceof HTMLTableRowElement)) return;
    const category = sanitizeCotizacionCategory(row.dataset.category || 'extras');
    if (!COTIZACION_SUBCONCEPTO_AUTO_HORA_CATEGORIES.has(category)) return;

    const subconceptSelect = row.querySelector('.cot-subconcepto');
    if (!(subconceptSelect instanceof HTMLInputElement || subconceptSelect instanceof HTMLSelectElement)) return;
    const selectedValue = String(subconceptSelect.value || '').trim();
    if (!selectedValue) return;

    const indiceControl = row.querySelector('.cot-indice');
    if (!(indiceControl instanceof HTMLInputElement || indiceControl instanceof HTMLSelectElement)) return;
    if (String(indiceControl.value || '').trim()) {
        row.dataset.lastIndice = normalizeCotizacionIndiceFromComplementarioUnit(indiceControl.value || '') || 'Horas';
        return;
    }

    setCotizacionSingleSelectValue(indiceControl, 'Horas', { dispatchEvents: false });
    row.dataset.lastIndice = 'Horas';
    updateCotizacionRowUnitPlaceholders(row);
}

function syncCotizacionRateToIndiceUnit(row, previousIndice = '', nextIndice = '') {
    if (!(row instanceof HTMLTableRowElement)) return;
    const category = sanitizeCotizacionCategory(row.dataset.category || 'extras');
    if (!isCotizacionTimeIndiceCategory(category)) return;

    const fromIndice = normalizeCotizacionIndiceFromComplementarioUnit(previousIndice || row.dataset.lastIndice || 'Horas') || 'Horas';
    const toIndice = normalizeCotizacionIndiceFromComplementarioUnit(nextIndice || row.querySelector('.cot-indice')?.value || 'Horas') || 'Horas';
    row.dataset.lastIndice = toIndice;

    if (fromIndice === toIndice) return;

    const rateInput = row.querySelector('.cot-rate');
    if (!(rateInput instanceof HTMLInputElement)) return;

    const formula = String(rateInput.dataset.formula || '').trim();
    if (formula.startsWith('=')) return;

    const currentRate = parseFloat(String(rateInput.dataset.preciseValue || rateInput.value || '').trim().replace(/,/g, '.'));
    if (!Number.isFinite(currentRate)) return;

    const fromFactor = getCotizacionIndiceConversionFactor(fromIndice);
    const toFactor = getCotizacionIndiceConversionFactor(toIndice);
    if (!Number.isFinite(fromFactor) || !Number.isFinite(toFactor) || fromFactor <= 0 || toFactor <= 0) return;

    const hourlyBase = currentRate / fromFactor;
    const convertedRate = hourlyBase * toFactor;
    setCotizacionNumericDisplayValue(rateInput, convertedRate);

    clearCotizacionApprovalSignature(false);
    applyCotizacionDefaultCostFormulaToRow(row, { force: true });
    updateCotizacionRowUnitPlaceholders(row);
}

function applyCotizacionSubconceptFieldForRow(row, options = {}) {
    if (!(row instanceof HTMLTableRowElement)) return;

    const category = sanitizeCotizacionCategory(row.dataset.category || 'extras');
    const cell = row.cells[1];
    if (!(cell instanceof HTMLTableCellElement)) return;

    const currentControl = row.querySelector('.cot-subconcepto');
    const currentValue = String(currentControl?.value || '').trim();

    cell.innerHTML = buildCotizacionSubconceptFieldHTML(category, currentValue);
    const textArea = cell.querySelector('.cot-autogrow');
    if (textArea instanceof HTMLTextAreaElement) {
        autoResizeCotizacionTextarea(textArea);
    }

    if (options.applyRateFromSelection) {
        syncCotizacionRateFromSubconceptRow(row, !!options.onlyIfEmptyRate);
    }
}

function getCotizacionMateriaPrimaPieces() {
    const rows = getCotizacionRows();
    const pieces = [];
    const seen = new Set();

    rows.forEach((row) => {
        if (!(row instanceof HTMLTableRowElement)) return;
        const category = sanitizeCotizacionCategory(row.dataset.category || 'extras');
        if (category !== 'materia_prima' && category !== 'conjunto') return;

        const rawValue = String(row.querySelector('.cot-pieza')?.value || '').trim();
        if (!rawValue) return;

        const dedupeKey = rawValue.toLowerCase();
        if (seen.has(dedupeKey)) return;

        seen.add(dedupeKey);
        pieces.push(rawValue);
    });

    return pieces;
}

function categoryUsesCotizacionPiezaDropdown(categoryKey) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    return COTIZACION_PIEZA_FROM_MATERIA_CATEGORIES.has(safeCategory);
}

function categoryUsesCotizacionPiezaMultiSelect(categoryKey) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    return COTIZACION_PIEZA_MULTISELECT_CATEGORIES.has(safeCategory);
}

function categoryUsesCotizacionAllPiecesOption(categoryKey) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    return safeCategory === 'ensamble' || safeCategory === 'embalaje';
}

function isCotizacionAllPiecesValue(rawValue) {
    const normalized = String(rawValue || '').trim().toLowerCase();
    return normalized === COTIZACION_PIEZA_ALL_VALUE || normalized === COTIZACION_PIEZA_ALL_LABEL.toLowerCase();
}

function parseCotizacionPieceSelections(rawValue) {
    const raw = String(rawValue || '').trim();
    if (!raw) return [];
    if (isCotizacionAllPiecesValue(raw)) return [COTIZACION_PIEZA_ALL_VALUE];

    const seen = new Set();
    return raw
        .split(COTIZACION_PIEZA_MULTI_SEPARATOR)
        .map((item) => String(item || '').trim())
        .filter((item) => {
            if (!item) return false;
            const key = item.toLowerCase();
            if (seen.has(key)) return false;
            seen.add(key);
            return true;
        });
}

function serializeCotizacionPieceSelections(selections) {
    const items = Array.isArray(selections) ? selections : [];
    if (items.some((item) => isCotizacionAllPiecesValue(item))) {
        return COTIZACION_PIEZA_ALL_VALUE;
    }

    const seen = new Set();
    return items
        .map((item) => String(item || '').trim())
        .filter((item) => {
            if (!item) return false;
            const key = item.toLowerCase();
            if (seen.has(key)) return false;
            seen.add(key);
            return true;
        })
        .join(COTIZACION_PIEZA_MULTI_SEPARATOR);
}

function formatCotizacionPieceDisplayValue(rawValue, joiner = ', ') {
    const selections = parseCotizacionPieceSelections(rawValue);
    if (!selections.length) return '-';
    if (selections.length === 1 && isCotizacionAllPiecesValue(selections[0])) {
        return COTIZACION_PIEZA_ALL_LABEL;
    }
    return selections.join(String(joiner || ', '));
}

function normalizeCotizacionPieceSelections(categoryKey, rawSelections, options = []) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    const validMap = new Map(options.map((item) => [String(item || '').trim().toLowerCase(), String(item || '').trim()]));
    const selections = Array.isArray(rawSelections) ? rawSelections : parseCotizacionPieceSelections(rawSelections);
    const normalized = [];
    const seen = new Set();

    selections.forEach((item) => {
        const raw = String(item || '').trim();
        if (!raw) return;

        if (categoryUsesCotizacionAllPiecesOption(safeCategory) && isCotizacionAllPiecesValue(raw) && options.length >= 2) {
            normalized.length = 0;
            normalized.push(COTIZACION_PIEZA_ALL_VALUE);
            return;
        }

        const valid = validMap.get(raw.toLowerCase());
        if (!valid) return;
        const key = valid.toLowerCase();
        if (seen.has(key)) return;
        seen.add(key);
        normalized.push(valid);
    });

    if (normalized.some((item) => isCotizacionAllPiecesValue(item))) {
        return [COTIZACION_PIEZA_ALL_VALUE];
    }

    return normalized;
}

function resolveCotizacionSelectedPieceNames(categoryKey, rawValue, availablePieces = []) {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    const selections = normalizeCotizacionPieceSelections(safeCategory, rawValue, availablePieces);
    if (!selections.length) return [];

    if (selections.length === 1 && isCotizacionAllPiecesValue(selections[0])) {
        return availablePieces.slice();
    }

    return selections;
}

function buildCotizacionPiezaFieldHTML(categoryKey, currentValue = '') {
    const safeCategory = sanitizeCotizacionCategory(categoryKey);
    const current = String(currentValue || '').trim();

    if (safeCategory === 'costo_byp') {
        return '<input type="text" class="cot-input cot-pieza cot-pieza-fixed" value="-" readonly>';
    }

    if (!categoryUsesCotizacionPiezaDropdown(safeCategory)) {
        return `<textarea rows="1" class="cot-input cot-pieza cot-autogrow">${escapeCotizacionHTML(current)}</textarea>`;
    }

    const options = getCotizacionMateriaPrimaPieces();
    if (categoryUsesCotizacionPiezaMultiSelect(safeCategory)) {
        const normalizedSelections = normalizeCotizacionPieceSelections(safeCategory, current, options);
        const serializedValue = serializeCotizacionPieceSelections(normalizedSelections);
        const triggerLabel = normalizedSelections.length
            ? formatCotizacionPieceDisplayValue(serializedValue, '\n')
            : 'Seleccionar...';
        const showAllOption = categoryUsesCotizacionAllPiecesOption(safeCategory) && options.length >= 2;

        let optionsHTML = '';
        if (showAllOption) {
            const isChecked = normalizedSelections.some((item) => isCotizacionAllPiecesValue(item));
            optionsHTML += `
                <label class="cot-pieza-multiselect-option">
                    <input type="checkbox" class="cot-pieza-multiselect-checkbox" value="${escapeCotizacionHTML(COTIZACION_PIEZA_ALL_VALUE)}" ${isChecked ? 'checked' : ''}>
                    <span>${escapeCotizacionHTML(COTIZACION_PIEZA_ALL_LABEL)}</span>
                </label>
            `;
        }

        options.forEach((pieceName) => {
            const safeName = String(pieceName || '').trim();
            if (!safeName) return;
            const isChecked = normalizedSelections.some((item) => String(item || '').trim().toLowerCase() === safeName.toLowerCase());
            optionsHTML += `
                <label class="cot-pieza-multiselect-option">
                    <input type="checkbox" class="cot-pieza-multiselect-checkbox" value="${escapeCotizacionHTML(safeName)}" ${isChecked ? 'checked' : ''}>
                    <span>${escapeCotizacionHTML(safeName)}</span>
                </label>
            `;
        });

        return `
            <div class="cot-pieza-multiselect" data-category="${escapeCotizacionHTML(safeCategory)}">
                <input type="hidden" class="cot-pieza cot-pieza-multiselect-value" value="${escapeCotizacionHTML(serializedValue)}">
                <button type="button" class="cot-input cot-pieza-multiselect-trigger">${escapeCotizacionHTML(triggerLabel)}</button>
                <div class="cot-pieza-multiselect-menu" style="display:none;">
                    ${optionsHTML || '<div class="cot-pieza-multiselect-empty">Sin piezas disponibles.</div>'}
                </div>
            </div>
        `;
    }

    const currentLower = current.toLowerCase();
    let hasCurrent = false;
    let optionsHTML = '<option value="">Seleccionar...</option>';

    if (categoryUsesCotizacionAllPiecesOption(safeCategory) && options.length >= 2) {
        const selectedAll = isCotizacionAllPiecesValue(current);
        if (selectedAll) hasCurrent = true;
        optionsHTML += `<option value="${escapeCotizacionHTML(COTIZACION_PIEZA_ALL_VALUE)}"${selectedAll ? ' selected' : ''}>${escapeCotizacionHTML(COTIZACION_PIEZA_ALL_LABEL)}</option>`;
    }

    options.forEach((pieceName) => {
        const selected = current && pieceName.toLowerCase() === currentLower;
        if (selected) hasCurrent = true;

        optionsHTML += `<option value="${escapeCotizacionHTML(pieceName)}"${selected ? ' selected' : ''}>${escapeCotizacionHTML(pieceName)}</option>`;
    });

    if (current && !hasCurrent) {
        const fallbackValue = isCotizacionAllPiecesValue(current) ? COTIZACION_PIEZA_ALL_VALUE : current;
        const fallbackLabel = isCotizacionAllPiecesValue(current) ? COTIZACION_PIEZA_ALL_LABEL : current;
        optionsHTML += `<option value="${escapeCotizacionHTML(fallbackValue)}" selected>${escapeCotizacionHTML(fallbackLabel)}</option>`;
    }

    const singleOptions = [];
    if (categoryUsesCotizacionAllPiecesOption(safeCategory) && options.length >= 2) {
        singleOptions.push({ value: COTIZACION_PIEZA_ALL_VALUE, label: COTIZACION_PIEZA_ALL_LABEL });
    }
    options.forEach((pieceName) => {
        singleOptions.push({ value: pieceName, label: pieceName });
    });
    if (current && !singleOptions.some((item) => item.value.toLowerCase() === current.toLowerCase())) {
        singleOptions.push({
            value: isCotizacionAllPiecesValue(current) ? COTIZACION_PIEZA_ALL_VALUE : current,
            label: isCotizacionAllPiecesValue(current) ? COTIZACION_PIEZA_ALL_LABEL : current
        });
    }

    return buildCotizacionSingleSelectHTML({
        controlClass: 'cot-pieza',
        wrapperClass: 'cot-pieza-select-wrap',
        currentValue: isCotizacionAllPiecesValue(current) ? COTIZACION_PIEZA_ALL_VALUE : current,
        placeholderText: 'Seleccionar...',
        options: singleOptions
    });
}

function applyCotizacionPiezaFieldForRow(row) {
    if (!(row instanceof HTMLTableRowElement)) return;

    const category = sanitizeCotizacionCategory(row.dataset.category || 'extras');
    const cell = row.cells[2];
    if (!(cell instanceof HTMLTableCellElement)) return;

    const currentControl = row.querySelector('.cot-pieza');
    const currentValue = String(currentControl?.value || '').trim();
    cell.innerHTML = buildCotizacionPiezaFieldHTML(category, currentValue);
    const textArea = cell.querySelector('.cot-autogrow');
    if (textArea instanceof HTMLTextAreaElement) {
        autoResizeCotizacionTextarea(textArea);
    }
}

function positionCotizacionPieceMultiselectMenu(wrapper, menu) {
    if (!(wrapper instanceof HTMLElement) || !(menu instanceof HTMLElement)) return;
    const trigger = wrapper.querySelector('.cot-pieza-multiselect-trigger');
    if (!(trigger instanceof HTMLButtonElement)) return;

    const rect = trigger.getBoundingClientRect();
    menu.style.position = 'fixed';
    menu.style.left = `${Math.round(rect.left)}px`;
    menu.style.top = `${Math.round(rect.bottom + 4)}px`;
    menu.style.width = `${Math.round(rect.width)}px`;
    menu.style.minWidth = `${Math.round(rect.width)}px`;
}

function closeCotizacionPieceMultiselectMenus(exceptWrapper = null) {
    const openState = window._cotizacionOpenPieceMultiselect || null;
    const wrapper = openState?.wrapper;
    const menu = openState?.menu;
    if (!(wrapper instanceof HTMLElement) || !(menu instanceof HTMLElement)) return;
    if (exceptWrapper instanceof HTMLElement && wrapper === exceptWrapper) return;

    wrapper.classList.remove('is-open');
    const cell = wrapper.closest('td');
    if (cell instanceof HTMLTableCellElement) {
        cell.classList.remove('is-open');
    }
    const row = wrapper.closest('tr');
    if (row instanceof HTMLTableRowElement) {
        row.classList.remove('cot-pieza-row-open');
    }

    wrapper.appendChild(menu);
    menu.style.display = 'none';
    menu.style.position = '';
    menu.style.left = '';
    menu.style.top = '';
    menu.style.width = '';
    menu.style.minWidth = '';
    window._cotizacionOpenPieceMultiselect = null;
}

function syncCotizacionPieceMultiselectState(wrapper, options = {}) {
    if (!(wrapper instanceof HTMLElement)) return;

    const category = sanitizeCotizacionCategory(wrapper.dataset.category || '');
    const hiddenInput = wrapper.querySelector('.cot-pieza-multiselect-value');
    const trigger = wrapper.querySelector('.cot-pieza-multiselect-trigger');
    if (!(hiddenInput instanceof HTMLInputElement) || !(trigger instanceof HTMLButtonElement)) return;

    const availablePieces = getCotizacionMateriaPrimaPieces();
    const openState = window._cotizacionOpenPieceMultiselect || null;
    const checkboxRoot = openState?.wrapper === wrapper && openState?.menu instanceof HTMLElement
        ? openState.menu
        : wrapper;
    const checkboxes = Array.from(checkboxRoot.querySelectorAll('.cot-pieza-multiselect-checkbox'))
        .filter((item) => item instanceof HTMLInputElement);

    let rawSelections = checkboxes.filter((item) => item.checked).map((item) => String(item.value || '').trim());
    rawSelections = normalizeCotizacionPieceSelections(category, rawSelections, availablePieces);

    const hasAllPieces = rawSelections.some((item) => isCotizacionAllPiecesValue(item));
    checkboxes.forEach((checkbox) => {
        const isAllOption = isCotizacionAllPiecesValue(checkbox.value);
        if (hasAllPieces && !isAllOption) {
            checkbox.checked = false;
        } else if (!hasAllPieces && isAllOption) {
            checkbox.checked = false;
        }
    });

    const serialized = serializeCotizacionPieceSelections(rawSelections);
    hiddenInput.value = serialized;
    trigger.textContent = rawSelections.length ? formatCotizacionPieceDisplayValue(serialized, '\n') : 'Seleccionar...';

    if (options.dispatchEvents) {
        hiddenInput.dispatchEvent(new Event('input', { bubbles: true }));
        hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
    }
}

function toggleCotizacionPieceMultiselect(wrapper) {
    if (!(wrapper instanceof HTMLElement)) return;
    const openStateMenu = window._cotizacionOpenPieceMultiselect?.wrapper === wrapper
        ? window._cotizacionOpenPieceMultiselect?.menu
        : null;
    const menu = openStateMenu instanceof HTMLElement
        ? openStateMenu
        : wrapper.querySelector('.cot-pieza-multiselect-menu');
    if (!(menu instanceof HTMLElement)) return;

    const willOpen = !wrapper.classList.contains('is-open');
    closeCotizacionPieceMultiselectMenus(willOpen ? wrapper : null);
    wrapper.classList.toggle('is-open', willOpen);
    const cell = wrapper.closest('td');
    if (cell instanceof HTMLTableCellElement) {
        cell.classList.toggle('is-open', willOpen);
    }
    const row = wrapper.closest('tr');
    if (row instanceof HTMLTableRowElement) {
        row.classList.toggle('cot-pieza-row-open', willOpen);
    }
    if (willOpen) {
        document.body.appendChild(menu);
        menu.style.display = 'block';
        positionCotizacionPieceMultiselectMenu(wrapper, menu);
        window._cotizacionOpenPieceMultiselect = { wrapper, menu };
    } else {
        wrapper.appendChild(menu);
        menu.style.display = 'none';
        menu.style.position = '';
        menu.style.left = '';
        menu.style.top = '';
        menu.style.width = '';
        menu.style.minWidth = '';
        window._cotizacionOpenPieceMultiselect = null;
    }
}

function positionCotizacionSingleSelectMenu(wrapper, menu) {
    if (!(wrapper instanceof HTMLElement) || !(menu instanceof HTMLElement)) return;
    const trigger = wrapper.querySelector('.cot-single-select-trigger');
    if (!(trigger instanceof HTMLButtonElement)) return;

    const rect = trigger.getBoundingClientRect();
    menu.style.position = 'fixed';
    menu.style.left = `${Math.round(rect.left)}px`;
    menu.style.top = `${Math.round(rect.bottom + 4)}px`;
    menu.style.width = `${Math.round(rect.width)}px`;
    menu.style.minWidth = `${Math.round(rect.width)}px`;
}

function closeCotizacionSingleSelectMenus(exceptWrapper = null) {
    const openState = window._cotizacionOpenSingleSelect || null;
    const wrapper = openState?.wrapper;
    const menu = openState?.menu;
    if (!(wrapper instanceof HTMLElement) || !(menu instanceof HTMLElement)) return;
    if (exceptWrapper instanceof HTMLElement && wrapper === exceptWrapper) return;

    wrapper.classList.remove('is-open');
    wrapper.appendChild(menu);
    menu.style.display = 'none';
    menu.style.position = '';
    menu.style.left = '';
    menu.style.top = '';
    menu.style.width = '';
    menu.style.minWidth = '';
    window._cotizacionOpenSingleSelect = null;
}

function syncCotizacionSingleSelectState(wrapper, selectedValue = '', options = {}) {
    if (!(wrapper instanceof HTMLElement)) return;

    const hiddenInput = wrapper.querySelector('.cot-single-select-value');
    const trigger = wrapper.querySelector('.cot-single-select-trigger');
    if (!(hiddenInput instanceof HTMLInputElement) || !(trigger instanceof HTMLButtonElement)) return;

    const rawValue = String(selectedValue ?? hiddenInput.value ?? '').trim();
    const optionRoot = window._cotizacionOpenSingleSelect?.wrapper === wrapper && window._cotizacionOpenSingleSelect?.menu instanceof HTMLElement
        ? window._cotizacionOpenSingleSelect.menu
        : wrapper;
    const optionButtons = Array.from(optionRoot.querySelectorAll('.cot-single-select-option'))
        .filter((button) => button instanceof HTMLButtonElement);
    const selectedButton = optionButtons.find((button) => String(button.dataset.value || '').trim().toLowerCase() === rawValue.toLowerCase()) || null;
    const placeholderText = String(wrapper.dataset.placeholder || 'Seleccionar...').trim() || 'Seleccionar...';
    const isPlaceholderSelection = !rawValue;

    hiddenInput.value = rawValue;
    hiddenInput.dataset.selectedRate = !isPlaceholderSelection && selectedButton ? String(selectedButton.dataset.rate || '').trim() : '';
    trigger.textContent = isPlaceholderSelection
        ? placeholderText
        : (selectedButton ? String(selectedButton.textContent || '').trim() : (rawValue || placeholderText));
    trigger.classList.toggle('is-placeholder', isPlaceholderSelection);

    optionButtons.forEach((button) => {
        button.classList.toggle('is-selected', button === selectedButton);
    });

    if (options.dispatchEvents) {
        hiddenInput.dispatchEvent(new Event('input', { bubbles: true }));
        hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
    }
}

function toggleCotizacionSingleSelect(wrapper) {
    if (!(wrapper instanceof HTMLElement)) return;
    const openStateMenu = window._cotizacionOpenSingleSelect?.wrapper === wrapper
        ? window._cotizacionOpenSingleSelect?.menu
        : null;
    const menu = openStateMenu instanceof HTMLElement
        ? openStateMenu
        : wrapper.querySelector('.cot-single-select-menu');
    if (!(menu instanceof HTMLElement)) return;

    const willOpen = !wrapper.classList.contains('is-open');
    closeCotizacionSingleSelectMenus(willOpen ? wrapper : null);
    wrapper.classList.toggle('is-open', willOpen);
    if (willOpen) {
        document.body.appendChild(menu);
        menu.style.display = 'block';
        positionCotizacionSingleSelectMenu(wrapper, menu);
        window._cotizacionOpenSingleSelect = { wrapper, menu };
    } else {
        wrapper.appendChild(menu);
        menu.style.display = 'none';
        menu.style.position = '';
        menu.style.left = '';
        menu.style.top = '';
        menu.style.width = '';
        menu.style.minWidth = '';
        window._cotizacionOpenSingleSelect = null;
    }
}

function setCotizacionSingleSelectValue(control, value, options = {}) {
    if (control instanceof HTMLSelectElement) {
        control.value = String(value || '').trim();
        if (options.dispatchEvents) {
            control.dispatchEvent(new Event('input', { bubbles: true }));
            control.dispatchEvent(new Event('change', { bubbles: true }));
        }
        return;
    }

    if (!(control instanceof HTMLInputElement)) return;
    const wrapper = control.closest('.cot-single-select');
    if (!(wrapper instanceof HTMLElement)) {
        control.value = String(value || '').trim();
        if (options.dispatchEvents) {
            control.dispatchEvent(new Event('input', { bubbles: true }));
            control.dispatchEvent(new Event('change', { bubbles: true }));
        }
        return;
    }

    syncCotizacionSingleSelectState(wrapper, String(value || '').trim(), options);
}

function handleCotizacionSingleSelectOptionClick(target, event) {
    if (!(target instanceof HTMLElement)) return;
    const option = target.closest('.cot-single-select-option');
    if (!(option instanceof HTMLButtonElement)) return;

    event.preventDefault();
    event.stopPropagation();
    const openState = window._cotizacionOpenSingleSelect || null;
    const wrapper = option.closest('.cot-single-select') || openState?.wrapper;
    if (!(wrapper instanceof HTMLElement)) return;

    syncCotizacionSingleSelectState(wrapper, String(option.dataset.value || '').trim(), { dispatchEvents: true });
    closeCotizacionSingleSelectMenus();
}

function handleCotizacionPieceMultiselectCheckboxChange(target) {
    if (!(target instanceof HTMLInputElement)) return;
    if (!target.classList.contains('cot-pieza-multiselect-checkbox')) return;

    const menu = target.closest('.cot-pieza-multiselect-menu');
    const openState = window._cotizacionOpenPieceMultiselect || null;
    const wrapper = target.closest('.cot-pieza-multiselect') || openState?.wrapper;
    if (!(menu instanceof HTMLElement) || !(wrapper instanceof HTMLElement)) return;

    if (target.checked && isCotizacionAllPiecesValue(target.value)) {
        menu.querySelectorAll('.cot-pieza-multiselect-checkbox').forEach((checkbox) => {
            if (!(checkbox instanceof HTMLInputElement)) return;
            if (checkbox === target) return;
            checkbox.checked = false;
        });
    } else if (target.checked) {
        const allCheckbox = Array.from(menu.querySelectorAll('.cot-pieza-multiselect-checkbox'))
            .find((checkbox) => checkbox instanceof HTMLInputElement && isCotizacionAllPiecesValue(checkbox.value));
        if (allCheckbox instanceof HTMLInputElement) {
            allCheckbox.checked = false;
        }
    }

    syncCotizacionPieceMultiselectState(wrapper, { dispatchEvents: true });
}

function handleCotizacionPieceMultiselectOptionClick(target, event) {
    if (!(target instanceof HTMLElement)) return;
    const option = target.closest('.cot-pieza-multiselect-option');
    if (!(option instanceof HTMLLabelElement)) return;
    if (target instanceof HTMLInputElement && target.classList.contains('cot-pieza-multiselect-checkbox')) return;

    event.preventDefault();
    const checkbox = option.querySelector('.cot-pieza-multiselect-checkbox');
    if (!(checkbox instanceof HTMLInputElement) || checkbox.disabled) return;
    checkbox.checked = !checkbox.checked;
    checkbox.dispatchEvent(new Event('change', { bubbles: true }));
}

function refreshCotizacionPiezaFields(syncReferences = false) {
    const rows = getCotizacionRows();
    rows.forEach((row) => {
        if (!(row instanceof HTMLTableRowElement)) return;
        const category = sanitizeCotizacionCategory(row.dataset.category || 'extras');
        if (!categoryUsesCotizacionPiezaDropdown(category)) return;
        applyCotizacionPiezaFieldForRow(row);
    });
    if (syncReferences) {
        refreshCotizacionCellReferences();
    }
}

function restoreCotizacionSplitCostDisplay(rows = getCotizacionRows()) {
    Array.from(rows || []).forEach((row) => {
        if (!(row instanceof HTMLTableRowElement)) return;
        const costInput = row.querySelector('.cot-cost');
        if (!(costInput instanceof HTMLInputElement)) return;
        if (!Object.prototype.hasOwnProperty.call(costInput.dataset, 'splitBaseFormula') &&
            !Object.prototype.hasOwnProperty.call(costInput.dataset, 'splitBaseValue')) {
            return;
        }

        costInput.dataset.formula = String(costInput.dataset.splitBaseFormula || '').trim();
        costInput.value = String(costInput.dataset.splitBaseValue || '');
        delete costInput.dataset.splitBaseFormula;
        delete costInput.dataset.splitBaseValue;
        delete costInput.dataset.splitDivisor;
    });
}

function applyCotizacionSplitCostDisplay(rows = getCotizacionRows(), availablePieceNames = []) {
    Array.from(rows || []).forEach((row) => {
        if (!(row instanceof HTMLTableRowElement)) return;

        const category = sanitizeCotizacionCategory(row.dataset.category || '');
        if (category === 'materia_prima' || category === 'conjunto' || category === 'complementarios') return;

        const costInput = row.querySelector('.cot-cost');
        if (!(costInput instanceof HTMLInputElement)) return;

        if (!Object.prototype.hasOwnProperty.call(costInput.dataset, 'splitBaseFormula')) {
            costInput.dataset.splitBaseFormula = String(costInput.dataset.formula || '').trim();
        }
        if (!Object.prototype.hasOwnProperty.call(costInput.dataset, 'splitBaseValue')) {
            costInput.dataset.splitBaseValue = String(costInput.value || '');
        }

        const selectedPieceCount = resolveCotizacionSelectedPieceNames(
            category,
            String(row.querySelector('.cot-pieza')?.value || '').trim(),
            availablePieceNames
        ).length;

        if (!Number.isFinite(selectedPieceCount) || selectedPieceCount <= 1) {
            costInput.dataset.formula = String(costInput.dataset.splitBaseFormula || '').trim();
            costInput.value = String(costInput.dataset.splitBaseValue || '');
            delete costInput.dataset.splitDivisor;
            return;
        }

        const baseFormula = String(costInput.dataset.splitBaseFormula || '').trim();
        const baseValueRaw = String(costInput.dataset.splitBaseValue || '').trim();
        const divisor = Math.max(1, selectedPieceCount);
        costInput.dataset.splitDivisor = String(divisor);

        if (baseFormula.startsWith('=')) {
            costInput.dataset.formula = `=(${baseFormula.slice(1)})/${divisor}`;
            evaluateCotizacionFormulaInput(costInput, { fromStored: true, silent: true });
            return;
        }

        costInput.dataset.formula = '';
        if (!baseValueRaw) {
            costInput.value = '';
            return;
        }

        const baseNumeric = parseFloat(baseValueRaw.replace(/,/g, '.'));
        costInput.value = Number.isFinite(baseNumeric)
            ? formatCotizacionFormulaValue(baseNumeric / divisor)
            : baseValueRaw;
    });
}

function isCotizacionComplementariosLookupControl(control) {
    if (!(control instanceof HTMLInputElement || control instanceof HTMLTextAreaElement)) return false;
    if (!control.classList.contains('cot-pieza') && !control.classList.contains('cot-descripcion')) return false;
    const row = control.closest('.cotizacion-item-row');
    if (!(row instanceof HTMLTableRowElement)) return false;
    const category = sanitizeCotizacionCategory(row.dataset.category || '');
    return category === 'complementarios';
}

function ensureCotizacionComplementariosLookupMenu() {
    let menu = document.getElementById('cotizacion-complementarios-lookup-menu');
    if (menu instanceof HTMLElement) return menu;

    menu = document.createElement('div');
    menu.id = 'cotizacion-complementarios-lookup-menu';
    menu.className = 'cotizacion-complementarios-lookup-menu';
    menu.style.display = 'none';

    menu.addEventListener('mousedown', (event) => {
        const target = event.target;
        if (!(target instanceof HTMLElement)) return;
        if (target.closest('.cotizacion-complementarios-lookup-item')) {
            event.preventDefault();
        }
    });

    menu.addEventListener('click', (event) => {
        const target = event.target;
        if (!(target instanceof HTMLElement)) return;
        const itemButton = target.closest('.cotizacion-complementarios-lookup-item');
        if (!(itemButton instanceof HTMLButtonElement)) return;

        const index = parseInt(String(itemButton.dataset.index || ''), 10);
        const context = window._cotizacionComplementariosLookupContext || null;
        const items = Array.isArray(context?.items) ? context.items : [];
        const row = context?.row;
        const selected = Number.isFinite(index) ? items[index] : null;

        if (!(row instanceof HTMLTableRowElement) || !selected || typeof selected !== 'object') {
            hideCotizacionComplementariosLookupMenu();
            return;
        }

        applyCotizacionComplementariosLookupSelection(row, selected);
        hideCotizacionComplementariosLookupMenu();
    });

    document.body.appendChild(menu);
    return menu;
}

function hideCotizacionComplementariosLookupMenu() {
    const menu = document.getElementById('cotizacion-complementarios-lookup-menu');
    if (menu instanceof HTMLElement) {
        menu.style.display = 'none';
        menu.innerHTML = '';
    }
    window._cotizacionComplementariosLookupContext = null;
}

function positionCotizacionComplementariosLookupMenu(anchorControl) {
    const menu = ensureCotizacionComplementariosLookupMenu();
    if (!(menu instanceof HTMLElement)) return;
    if (!(anchorControl instanceof HTMLElement)) return;

    const rect = anchorControl.getBoundingClientRect();
    const viewportWidth = window.innerWidth || document.documentElement.clientWidth || 0;
    const preferredWidth = Math.max(rect.width, 420);
    const width = Math.min(preferredWidth, Math.max(260, viewportWidth - 24));
    const left = Math.max(8, Math.min(rect.left, viewportWidth - width - 8));
    const top = rect.bottom + 4;

    menu.style.left = `${Math.round(left)}px`;
    menu.style.top = `${Math.round(top)}px`;
    menu.style.width = `${Math.round(width)}px`;
}

function formatCotizacionComplementariosLookupPrice(rawValue) {
    const numeric = Number(rawValue);
    if (!Number.isFinite(numeric)) return 'Sin precio';
    return formatCotizacionCurrency(numeric);
}

function renderCotizacionComplementariosLookupMenu(anchorControl, items = []) {
    const menu = ensureCotizacionComplementariosLookupMenu();
    if (!(menu instanceof HTMLElement)) return;

    if (!Array.isArray(items) || !items.length) {
        hideCotizacionComplementariosLookupMenu();
        return;
    }

    menu.innerHTML = items.map((item, index) => {
        const pieza = String(item?.pieza || '').trim();
        const descripcion = String(item?.descripcion || '').trim();
        const precio = formatCotizacionComplementariosLookupPrice(item?.precio);
        const principal = pieza || descripcion || '-';
        const secondary = descripcion && descripcion !== principal ? descripcion : '';

        return `
            <button type="button" class="cotizacion-complementarios-lookup-item" data-index="${index}">
                <span class="cotizacion-complementarios-lookup-main">${escapeCotizacionHTML(principal)}</span>
                <span class="cotizacion-complementarios-lookup-sub">${escapeCotizacionHTML(secondary || '-')}</span>
                <span class="cotizacion-complementarios-lookup-price">${escapeCotizacionHTML(precio)}</span>
            </button>
        `;
    }).join('');

    positionCotizacionComplementariosLookupMenu(anchorControl);
    menu.style.display = 'block';
}

async function refreshCotizacionComplementariosCSV(showMessage = false) {
    try {
        const response = await fetch(COTIZACION_COMPLEMENTARIOS_REFRESH_ENDPOINT, { method: 'POST' });
        let data = null;
        try {
            data = await response.json();
        } catch {
            data = null;
        }

        if (!response.ok || !data || data.status !== 'success') {
            if (showMessage) {
                showNotification(data?.message || 'No se pudo actualizar la base CSV de complementarios.', 'warning');
            }
            return false;
        }

        if (showMessage) {
            const rows = Number(data.rows || 0);
            showNotification(`CSV de complementarios actualizado (${rows} items).`, 'success');
        }
        return true;
    } catch (error) {
        console.error(error);
        if (showMessage) {
            showNotification('Error al actualizar el CSV de complementarios.', 'warning');
        }
        return false;
    }
}

async function refreshCotizacionComplementariosCSVOnEntry() {
    const now = Date.now();
    const lastRefresh = Number(window._cotizacionComplementariosLastRefreshTs || 0);
    const minIntervalMs = 20000;

    if (window._cotizacionComplementariosRefreshInFlight) return false;
    if (lastRefresh > 0 && (now - lastRefresh) < minIntervalMs) return false;

    window._cotizacionComplementariosRefreshInFlight = true;
    try {
        const ok = await refreshCotizacionComplementariosCSV(false);
        if (ok) {
            window._cotizacionComplementariosLastRefreshTs = Date.now();
        }
        return ok;
    } finally {
        window._cotizacionComplementariosRefreshInFlight = false;
    }
}

async function fetchCotizacionComplementariosLookup(query, field = 'pieza') {
    const safeQuery = String(query || '').trim();
    if (!safeQuery || safeQuery.length < COTIZACION_COMPLEMENTARIOS_LOOKUP_MIN_CHARS) {
        return [];
    }

    const params = new URLSearchParams();
    params.set('q', safeQuery);
    params.set('field', field === 'descripcion' ? 'descripcion' : 'pieza');
    params.set('limit', String(COTIZACION_COMPLEMENTARIOS_LOOKUP_LIMIT));

    const response = await fetch(`${COTIZACION_COMPLEMENTARIOS_LOOKUP_ENDPOINT}?${params.toString()}`);
    let data = null;
    try {
        data = await response.json();
    } catch {
        data = null;
    }

    if (!response.ok || !data || data.status !== 'success' || !Array.isArray(data.data)) {
        if (!window._cotizacionComplementariosLookupErrorShown) {
            window._cotizacionComplementariosLookupErrorShown = true;
            showNotification('No se pudo cargar la base de complementarios. Verifique el servidor de Cotizacion.', 'warning');
        }
        return [];
    }

    window._cotizacionComplementariosLookupErrorShown = false;
    return data.data;
}

function applyCotizacionComplementariosLookupSelection(row, item) {
    if (!(row instanceof HTMLTableRowElement) || !item || typeof item !== 'object') return;

    const pieceValue = String(item.pieza || '').trim();
    const descriptionValue = String(item.descripcion || '').trim();
    const rateValue = Number(item.precio);

    const pieceInput = row.querySelector('.cot-pieza');
    if (pieceInput instanceof HTMLInputElement || pieceInput instanceof HTMLTextAreaElement) {
        pieceInput.value = pieceValue;
        if (pieceInput instanceof HTMLTextAreaElement) {
            autoResizeCotizacionTextarea(pieceInput);
        }
    }

    const descriptionInput = row.querySelector('.cot-descripcion');
    if (descriptionInput instanceof HTMLInputElement || descriptionInput instanceof HTMLTextAreaElement) {
        descriptionInput.value = descriptionValue;
        if (descriptionInput instanceof HTMLTextAreaElement) {
            autoResizeCotizacionTextarea(descriptionInput);
        }
    }

    const rateInput = row.querySelector('.cot-rate');
    if (rateInput instanceof HTMLInputElement) {
        rateInput.dataset.formula = '';
        rateInput.value = Number.isFinite(rateValue) ? formatCotizacionFormulaValue(rateValue) : '';
    }

    const indiceControl = row.querySelector('.cot-indice');
    if (indiceControl instanceof HTMLInputElement || indiceControl instanceof HTMLSelectElement) {
        const targetIndice = normalizeCotizacionIndiceFromComplementarioUnit(item.unidad) || 'Unidades';
        setCotizacionSingleSelectValue(indiceControl, targetIndice, { dispatchEvents: false });
    }

    updateCotizacionRowUnitPlaceholders(row);
    recalculateCotizacionFormulaCells();
    clearCotizacionApprovalSignature(false);
    updateCotizacionSummary();
}

function scheduleCotizacionComplementariosLookup(control) {
    if (!isCotizacionComplementariosLookupControl(control)) {
        hideCotizacionComplementariosLookupMenu();
        return;
    }

    const query = String(control.value || '').trim();
    if (!query || query.length < COTIZACION_COMPLEMENTARIOS_LOOKUP_MIN_CHARS) {
        hideCotizacionComplementariosLookupMenu();
        return;
    }

    const row = control.closest('.cotizacion-item-row');
    if (!(row instanceof HTMLTableRowElement)) {
        hideCotizacionComplementariosLookupMenu();
        return;
    }

    const field = control.classList.contains('cot-descripcion') ? 'descripcion' : 'pieza';
    const requestToken = Number(window._cotizacionComplementariosLookupToken || 0) + 1;
    window._cotizacionComplementariosLookupToken = requestToken;

    if (window._cotizacionComplementariosLookupTimer) {
        clearTimeout(window._cotizacionComplementariosLookupTimer);
    }

    window._cotizacionComplementariosLookupTimer = setTimeout(async () => {
        let items = [];
        try {
            items = await fetchCotizacionComplementariosLookup(query, field);
        } catch (error) {
            console.error(error);
            items = [];
        }

        if (requestToken !== window._cotizacionComplementariosLookupToken) return;
        if (!document.body.contains(control) || !document.body.contains(row)) {
            hideCotizacionComplementariosLookupMenu();
            return;
        }

        if (!Array.isArray(items) || !items.length) {
            hideCotizacionComplementariosLookupMenu();
            return;
        }

        window._cotizacionComplementariosLookupContext = { row, control, items, field };
        renderCotizacionComplementariosLookupMenu(control, items);
    }, COTIZACION_COMPLEMENTARIOS_LOOKUP_DEBOUNCE_MS);
}

function handleCotizacionComplementariosLookupInputEvent(event) {
    const target = event.target;
    if (!(target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement)) return;
    scheduleCotizacionComplementariosLookup(target);
}

function handleCotizacionComplementariosLookupFocusOutEvent(event) {
    const target = event.target;
    if (!(target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement)) return;
    if (!isCotizacionComplementariosLookupControl(target)) return;

    setTimeout(() => {
        const active = document.activeElement;
        const menu = document.getElementById('cotizacion-complementarios-lookup-menu');
        if (menu instanceof HTMLElement && active instanceof HTMLElement && menu.contains(active)) return;
        hideCotizacionComplementariosLookupMenu();
    }, 140);
}

function handleCotizacionComplementariosLookupKeyDownEvent(event) {
    const target = event.target;
    if (!(target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement)) return;
    if (!isCotizacionComplementariosLookupControl(target)) return;
    if (event.key === 'Escape') {
        hideCotizacionComplementariosLookupMenu();
    }
}

function handleCotizacionComplementariosLookupDocumentMouseDown(event) {
    const target = event.target;
    if (!(target instanceof HTMLElement)) {
        hideCotizacionComplementariosLookupMenu();
        return;
    }

    const menu = document.getElementById('cotizacion-complementarios-lookup-menu');
    if (menu instanceof HTMLElement && menu.contains(target)) return;
    if (isCotizacionComplementariosLookupControl(target)) return;
    hideCotizacionComplementariosLookupMenu();
}

function ensureCotizacionProviderSuggestionsList() {
    let list = document.getElementById('cotizacion-provider-suggestions');
    if (list instanceof HTMLDataListElement) return list;

    list = document.createElement('datalist');
    list.id = 'cotizacion-provider-suggestions';
    document.body.appendChild(list);
    return list;
}

async function fetchCotizacionProviderSuggestions(query) {
    const safeQuery = String(query || '').trim();
    if (!safeQuery || safeQuery.length < COTIZACION_PROVIDER_LOOKUP_MIN_CHARS) {
        return [];
    }

    const params = new URLSearchParams();
    params.set('q', safeQuery);
    params.set('limit', String(COTIZACION_PROVIDER_LOOKUP_LIMIT));

    const response = await fetch(`${COTIZACION_PROVIDER_LOOKUP_ENDPOINT}?${params.toString()}`);
    let data = null;
    try {
        data = await response.json();
    } catch {
        data = null;
    }

    if (!response.ok || !data || data.status !== 'success' || !Array.isArray(data.data)) {
        return [];
    }

    return data.data.map((item) => String(item || '').trim()).filter(Boolean);
}

function scheduleCotizacionProviderSuggestions(control) {
    if (!(control instanceof HTMLInputElement) || !control.classList.contains('cot-proveedor')) return;
    const query = String(control.value || '').trim();
    const list = ensureCotizacionProviderSuggestionsList();
    control.setAttribute('list', 'cotizacion-provider-suggestions');

    if (!query || query.length < COTIZACION_PROVIDER_LOOKUP_MIN_CHARS) {
        list.innerHTML = '';
        return;
    }

    const token = Number(window._cotizacionProviderLookupToken || 0) + 1;
    window._cotizacionProviderLookupToken = token;

    if (window._cotizacionProviderLookupTimer) {
        clearTimeout(window._cotizacionProviderLookupTimer);
    }

    window._cotizacionProviderLookupTimer = setTimeout(async () => {
        let providers = [];
        try {
            providers = await fetchCotizacionProviderSuggestions(query);
        } catch (error) {
            console.error(error);
            providers = [];
        }

        if (token !== window._cotizacionProviderLookupToken) return;
        if (!document.body.contains(control)) return;

        list.innerHTML = providers
            .map((provider) => `<option value="${escapeCotizacionHTML(provider)}"></option>`)
            .join('');
    }, COTIZACION_PROVIDER_LOOKUP_DEBOUNCE_MS);
}

function buildCotizacionIndiceFieldHTML(categoryKey = '', currentValue = '') {
    const current = normalizeCotizacionIndiceFromComplementarioUnit(currentValue);
    const options = getCotizacionIndiceOptionsForCategory(categoryKey).map((optionValue) => ({
        value: optionValue,
        label: optionValue
    }));
    if (current && !options.some((item) => item.value.toLowerCase() === current.toLowerCase())) {
        options.push({ value: current, label: current });
    }

    return buildCotizacionSingleSelectHTML({
        controlClass: 'cot-indice',
        wrapperClass: 'cot-indice-select-wrap',
        currentValue: current || (isCotizacionTimeIndiceCategory(categoryKey) ? 'Horas' : current),
        placeholderText: 'Seleccionar...',
        options
    });
}

function refreshCotizacionSubconceptFields() {
    const rows = getCotizacionRows();
    rows.forEach((row) => {
        if (!(row instanceof HTMLTableRowElement)) return;
        applyCotizacionSubconceptFieldForRow(row, {
            applyRateFromSelection: true,
            onlyIfEmptyRate: true
        });
    });

    refreshCotizacionPiezaFields(false);
    refreshCotizacionCellReferences();
    refreshCotizacionUnitPlaceholders();
    updateCotizacionSummary();
}

async function loadCotizacionSubconceptOptions(showMessage = false) {
    if (window._cotizacionSubconceptOptionsLoaded) {
        return window._cotizacionSubconceptOptionsMap || {};
    }

    if (window._cotizacionSubconceptOptionsPromise) {
        return window._cotizacionSubconceptOptionsPromise;
    }

    window._cotizacionSubconceptOptionsPromise = (async () => {
        const response = await fetch('/api/cotizacion/indices');
        let data = null;

        try {
            data = await response.json();
        } catch {
            data = null;
        }

        if (!response.ok && (!data || !data.data)) {
            const errMsg = data?.message || 'No se pudieron cargar los indices de maquinas.';
            throw new Error(errMsg);
        }

        if (!data || (data.status !== 'success' && data.status !== 'partial')) {
            const errMsg = data?.message || 'Respuesta invalida de indices de cotizacion.';
            throw new Error(errMsg);
        }

        const incoming = (data && typeof data.data === 'object' && data.data) ? data.data : {};
        const normalized = {};

        COTIZACION_CATEGORY_CONFIG.forEach((cfg) => {
            const rawList = Array.isArray(incoming[cfg.key]) ? incoming[cfg.key] : [];
            normalized[cfg.key] = rawList
                .map((item) => {
                    const subconcepto = String(item?.subconcepto || '').trim();
                    const rate = Number(item?.rate);
                    if (!subconcepto || !Number.isFinite(rate)) return null;
                    return { subconcepto, rate };
                })
                .filter(Boolean);
        });

        window._cotizacionSubconceptOptionsMap = normalized;
        window._cotizacionSubconceptOptionsLoaded = true;

        if (data.status === 'partial' && showMessage) {
            showNotification('Se cargaron indices parciales para Cotizacion.', 'warning');
        }

        return normalized;
    })();

    try {
        return await window._cotizacionSubconceptOptionsPromise;
    } catch (e) {
        window._cotizacionSubconceptOptionsMap = {};
        window._cotizacionSubconceptOptionsLoaded = false;
        if (showMessage) {
            showNotification(String(e?.message || 'No se pudieron cargar los indices de maquinas.'), 'warning');
        }
        throw e;
    } finally {
        window._cotizacionSubconceptOptionsPromise = null;
    }
}

function runCotizacionProgrammaticUpdate(fn) {
    window._cotizacionProgrammaticUpdate = true;
    try {
        return fn();
    } finally {
        window._cotizacionProgrammaticUpdate = false;
    }
}

function resolveCotizacionApprovalValue() {
    const signature = String(currentUserSignature || '').trim();
    if (signature) return signature;
    return String(currentDisplayName || currentUser || '').trim();
}

function resolveCotizacionPieceCode(recordOrHeader = null) {
    const source = recordOrHeader && typeof recordOrHeader === 'object'
        ? (recordOrHeader.header && typeof recordOrHeader.header === 'object' ? recordOrHeader.header : recordOrHeader)
        : {};
    return String(source.piece_code || source.code || '').trim();
}

function resolveCotizacionRequester(recordOrHeader = null) {
    const source = recordOrHeader && typeof recordOrHeader === 'object'
        ? (recordOrHeader.header && typeof recordOrHeader.header === 'object' ? recordOrHeader.header : recordOrHeader)
        : {};
    return String(source.requested_by || source.requester || '').trim();
}

function buildCotizacionRecordSaveName(code = '', piece = '') {
    const safeCode = String(code || '').trim();
    const safePiece = String(piece || '').trim();
    if (safeCode && safePiece) return `${safeCode} - ${safePiece}`;
    return safePiece || safeCode;
}

function resolveCotizacionRecordPieceName(record = null) {
    const explicitPiece = String(record?.header?.piece || '').trim();
    if (explicitPiece) return explicitPiece;
    const rawName = String(record?.save_name || '').trim();
    const code = resolveCotizacionPieceCode(record);
    if (rawName && code) {
        const prefix = `${code} - `;
        if (rawName.startsWith(prefix)) return rawName.slice(prefix.length).trim();
    }
    return rawName;
}


function clearCotizacionApprovalSignature(showMessage = false) {
    const input = document.getElementById('cot-approved-by');
    if (!input) return;

    if (input.value) {
        input.value = '';
        if (showMessage) {
            showNotification('Aprobacion eliminada.', 'info');
        }
    } else if (showMessage) {
        showNotification('No hay aprobacion para eliminar.', 'warning');
    }
}

function applyCotizacionApprovalSignature() {
    const input = document.getElementById('cot-approved-by');
    if (!input) return;

    const value = resolveCotizacionApprovalValue();
    if (!value) {
        showNotification('No hay firma configurada para este usuario.', 'warning');
        return;
    }

    input.value = value;
    showNotification('Aprobacion aplicada.', 'success');
}

async function refreshCotizacionDollarRate(showMessage = false, selectedDate = '') {
    const usdInput = document.getElementById('cot-usd-value');
    const usdDateInput = document.getElementById('cot-usd-date');
    if (!usdInput) return;

    const normalizedDate = String(selectedDate || '').trim();
    const url = normalizedDate
        ? `/api/cotizacion/dolar-rate?date=${encodeURIComponent(normalizedDate)}`
        : '/api/cotizacion/dolar-rate';

    try {
        const response = await fetch(url);
        const data = await response.json();

        if (response.ok && data && data.status === 'success' && Number(data.value) > 0) {
            usdInput.value = Number(data.value).toFixed(2);
            const labelDate = String(data.date || normalizedDate || '').trim();
            if (usdDateInput instanceof HTMLInputElement) {
                usdDateInput.value = normalizedDate ? (labelDate || '') : '';
            }
            setCotizacionDollarLabel(labelDate);
            if (showMessage) {
                showNotification(
                    labelDate
                        ? `Dolar Oficial (venta) actualizado para ${formatCotizacionDisplayDate(labelDate)}.`
                        : 'Dolar Oficial (venta) actualizado.',
                    'success'
                );
            }
            return;
        }

        if (showMessage) {
            showNotification(data.message || 'No se pudo obtener el valor del dolar Oficial venta.', 'warning');
        }
    } catch (e) {
        console.error(e);
        if (showMessage) {
            showNotification('Error al consultar el valor del dolar Oficial venta.', 'error');
        }
    }
}

function applyCotizacionUserContext() {
    const nameInput = document.getElementById('cot-resp-name');
    const positionInput = document.getElementById('cot-resp-position');
    const deptInput = document.getElementById('cot-resp-dept');
    const ownerInput = document.getElementById('cot-resp-owner');

    if (nameInput) nameInput.value = currentDisplayName || currentUser || '';
    if (positionInput) {
        positionInput.value = currentUserPosition || '';
        positionInput.readOnly = true;
    }
    if (deptInput) {
        deptInput.value = currentUserDepartment || '';
        deptInput.readOnly = true;
    }
    if (ownerInput) {
        ownerInput.value = COTIZACION_RESPONSABLE_FIJO;
        ownerInput.readOnly = true;
    }
}

function sanitizeCotizacionCategory(raw) {
    const allowed = new Set(COTIZACION_CATEGORY_CONFIG.map((item) => item.key));
    const key = String(raw || '').trim().toLowerCase();
    if (allowed.has(key)) return key;
    const alias = COTIZACION_CATEGORY_ALIASES[key];
    if (alias && allowed.has(alias)) return alias;

    const normalized = key
        .replace(/[^\w\s]/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
    if (allowed.has(normalized)) return normalized;
    const aliasNormalized = COTIZACION_CATEGORY_ALIASES[normalized];
    if (aliasNormalized && allowed.has(aliasNormalized)) return aliasNormalized;

    return 'extras';
}

function updateCotizacionSetupItemState(key) {
    const checkbox = document.getElementById(`cot-config-${key}-check`);
    const qtyInput = document.getElementById(`cot-config-${key}-rows`);
    if (!checkbox || !qtyInput) return;

    const enabled = !!checkbox.checked;
    qtyInput.disabled = !enabled;

    const item = checkbox.closest('.cotizacion-setup-item');
    if (item) {
        item.classList.toggle('is-disabled', !enabled);
    }
}

function resetCotizacionSetup() {
    COTIZACION_CATEGORY_CONFIG.forEach((cfg) => {
        const checkbox = document.getElementById(`cot-config-${cfg.key}-check`);
        const qtyInput = document.getElementById(`cot-config-${cfg.key}-rows`);

        if (checkbox) checkbox.checked = !!cfg.defaultChecked;
        if (qtyInput) qtyInput.value = '';

        updateCotizacionSetupItemState(cfg.key);
    });
}

function ensureCotizacionConfigBindings() {
    if (window._cotizacionConfigBindingsReady) return;

    COTIZACION_CATEGORY_CONFIG.forEach((cfg) => {
        const checkbox = document.getElementById(`cot-config-${cfg.key}-check`);
        const qtyInput = document.getElementById(`cot-config-${cfg.key}-rows`);

        if (checkbox) {
            checkbox.addEventListener('change', () => {
                updateCotizacionSetupItemState(cfg.key);
            });
        }

        if (qtyInput) {
            qtyInput.addEventListener('change', () => {
                const raw = String(qtyInput.value || '').trim();
                if (!raw) return;

                let parsed = parseInt(raw, 10);
                if (!Number.isFinite(parsed) || parsed < 1) parsed = 1;
                if (parsed > 50) parsed = 50;
                qtyInput.value = String(parsed);
            });
        }
    });

    const usdDateInput = document.getElementById('cot-usd-date');
    if (usdDateInput instanceof HTMLInputElement) {
        usdDateInput.addEventListener('change', () => {
            const selectedDate = String(usdDateInput.value || '').trim();
            if (!selectedDate) {
                setCotizacionDollarLabel('');
                return;
            }
            refreshCotizacionDollarRate(true, selectedDate).catch(() => { });
        });
    }

    window._cotizacionConfigBindingsReady = true;
}

function getCotizacionSetupSelection(requireQuantity = false) {
    const rows = [];
    const missing = [];

    COTIZACION_CATEGORY_CONFIG.forEach((cfg) => {
        const checkbox = document.getElementById(`cot-config-${cfg.key}-check`);
        const qtyInput = document.getElementById(`cot-config-${cfg.key}-rows`);
        const isChecked = !!checkbox && checkbox.checked;

        if (!isChecked) return;

        const rawQty = String(qtyInput?.value ?? '').trim();
        const defaultQtyRaw = parseInt(String(cfg.defaultRows ?? 1), 10);
        const defaultQty = Number.isFinite(defaultQtyRaw) && defaultQtyRaw >= 1 ? Math.min(50, defaultQtyRaw) : 1;
        let qty = defaultQty;

        if (rawQty) {
            const parsed = parseInt(rawQty, 10);
            if (Number.isFinite(parsed)) {
                qty = Math.min(50, Math.max(1, parsed));
            } else if (requireQuantity) {
                missing.push(cfg.label);
            }
        }

        for (let i = 0; i < qty; i += 1) {
            rows.push({
                category: cfg.key,
                categoria: cfg.label
            });
        }
    });

    return { rows, missing };
}

