// Global storage for re-rendering
let lastLogisticsData = null;
let lastContainerData = null;
let lastLogisticsMaximize = false;
let currentLogisticsJobId = null;
let logisticsProgressTimer = null;
let lastLogisticsRecords = [];
let lastLogisticsFolders = ['Sin Carpeta'];
let currentLogisticsFolder = 'Sin Carpeta';
let currentLogisticsRecordsFolderView = '';
window._logisticsMoveMode = false;

const LOGISTICS_PROGRESS_STAGES = [
    { key: 'queued', label: 'En cola' },
    { key: 'validation', label: 'Preparación' },
    { key: 'maximize', label: 'Maximización' },
    { key: 'tray', label: 'Bandejas' },
    { key: 'pallet', label: 'Pallets' },
    { key: 'solver', label: 'Empaquetado' },
    { key: 'summary', label: 'Resumen' },
    { key: 'done', label: 'Completado' }
];

function setLogisticsCancelVisibility(isVisible) {
    const btn = document.getElementById('btn-cancel-logistics');
    if (!btn) return;
    btn.style.display = isVisible ? 'block' : 'none';
    btn.disabled = false;
    btn.textContent = 'CANCELAR CÁLCULO';
}

function setLogistics3DNoteVisibility(isVisible) {
    const note = document.getElementById('logistics-3d-note');
    if (!note) return;
    note.style.display = isVisible ? 'block' : 'none';
}

async function cancelLogisticsCalculation() {
    if (!currentLogisticsJobId) return;

    const btn = document.getElementById('btn-cancel-logistics');
    if (btn) {
        btn.disabled = true;
        btn.textContent = 'CANCELANDO...';
    }

    try {
        const response = await fetch(`/api/logistics/calculate-cancel/${currentLogisticsJobId}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok || data.status !== 'ok') {
            throw new Error(data.message || 'No se pudo cancelar el cálculo.');
        }
        updateLogisticsProgress(0, 'Cancelando cálculo...', 'queued', 'Cancelando cálculo...');
        if (typeof showNotification === 'function') {
            showNotification(data.message || 'Solicitud de cancelación enviada.', 'info');
        }
    } catch (error) {
        console.error('Cancel logistics calculation failed', error);
        if (btn) {
            btn.disabled = false;
            btn.textContent = 'CANCELAR CÁLCULO';
        }
        if (typeof showNotification === 'function') {
            showNotification(error.message || 'No se pudo cancelar el cálculo.', 'error');
        }
    }
}

function startLogisticsProgress() {
    const wrapper = document.getElementById('logistics-progress-wrapper');
    const bar = document.getElementById('logistics-progress-bar');
    const text = document.getElementById('logistics-progress-text');
    const stageLabel = document.getElementById('logistics-progress-stage-label');
    const detail = document.getElementById('logistics-progress-detail');
    if (!wrapper || !bar || !text || !stageLabel || !detail) return;

    wrapper.style.display = 'block';
    bar.style.width = '0%';
    text.textContent = '0%';
    stageLabel.textContent = 'Preparando cálculo';
    detail.textContent = 'Iniciando...';
}

function updateLogisticsProgress(progress = 0, message = 'Procesando...', stage = 'queued', detail = '') {
    const wrapper = document.getElementById('logistics-progress-wrapper');
    const bar = document.getElementById('logistics-progress-bar');
    const text = document.getElementById('logistics-progress-text');
    const stageLabel = document.getElementById('logistics-progress-stage-label');
    const detailEl = document.getElementById('logistics-progress-detail');
    if (!wrapper || !bar || !text || !stageLabel || !detailEl) return;
    wrapper.style.display = 'block';
    const boundedProgress = Math.max(0, Math.min(100, progress));
    const stageInfo = LOGISTICS_PROGRESS_STAGES.find(item => item.key === stage);
    bar.style.width = `${boundedProgress}%`;
    text.textContent = `${boundedProgress}%`;
    stageLabel.textContent = stageInfo ? stageInfo.label : 'Procesando';
    detailEl.textContent = detail || message || 'Procesando...';
}

function finishLogisticsProgress(success = true, message = null) {
    const wrapper = document.getElementById('logistics-progress-wrapper');
    const bar = document.getElementById('logistics-progress-bar');
    const text = document.getElementById('logistics-progress-text');
    const stageLabel = document.getElementById('logistics-progress-stage-label');
    const detail = document.getElementById('logistics-progress-detail');
    if (!wrapper || !bar || !text || !stageLabel || !detail) return;

    bar.style.width = success ? '100%' : '0%';
    text.textContent = success ? '100%' : '0%';
    stageLabel.textContent = success ? 'Completado' : 'Interrumpido';
    detail.textContent = success ? (message || 'Cálculo completado') : (message || 'Cálculo interrumpido');

    setTimeout(() => {
        wrapper.style.display = 'none';
        bar.style.width = '0%';
        text.textContent = '0%';
        stageLabel.textContent = 'Preparando cálculo';
        detail.textContent = 'En cola...';
    }, success ? 700 : 0);
}

function validateLogisticsWeightLimits({ items, loadType, palletType, trayDims, palletDims, maxPalletWeight, container }) {
    const safeItems = Array.isArray(items) ? items : [];
    if (safeItems.length === 0) return null;

    const trayLoadTypes = ['tray', 'tray_euro', 'tray_american', 'tray_custom'];
    const isTrayType = trayLoadTypes.includes(loadType);
    const hasPallet = palletType && palletType !== 'none';
    const hasContainer = container && container.type && container.type !== 'none';

    const trayLoadLimit = Number(trayDims?.max_weight || 25);
    const trayTare = Number(trayDims?.weight || 0);
    const palletBaseWeight = Number(palletDims?.weight || 0);
    const palletGrossLimit = Number(maxPalletWeight || 0) > 0 ? Number(maxPalletWeight) : 2000;
    const containerGrossLimit = Number(container?.max_weight || 0);

    const itemWeights = safeItems
        .map(item => ({
            name: item.id || item.name || 'Item',
            weight: Number(item.weight || 0)
        }))
        .filter(item => Number.isFinite(item.weight) && item.weight > 0);

    if (itemWeights.length === 0) return null;

    const lightestItem = itemWeights.reduce((min, item) => item.weight < min.weight ? item : min, itemWeights[0]);

    if (isTrayType) {
        const trayBlockedItem = itemWeights.find(item => item.weight > trayLoadLimit);
        if (trayBlockedItem) {
            return `El item "${trayBlockedItem.name}" pesa ${trayBlockedItem.weight.toFixed(2)} kg y supera el límite de carga de la bandeja (${trayLoadLimit.toFixed(2)} kg).`;
        }
    }

    if (hasPallet) {
        if (isTrayType) {
            const minTrayGross = trayTare + lightestItem.weight;
            if ((palletBaseWeight + minTrayGross) > palletGrossLimit) {
                return `El pallet no admite ni una bandeja cargada mínima: base ${palletBaseWeight.toFixed(2)} kg + bandeja ${trayTare.toFixed(2)} kg + item ${lightestItem.weight.toFixed(2)} kg > límite de pallet ${palletGrossLimit.toFixed(2)} kg.`;
            }
        } else {
            const palletBlockedItem = itemWeights.find(item => (palletBaseWeight + item.weight) > palletGrossLimit);
            if (palletBlockedItem) {
                return `El item "${palletBlockedItem.name}" supera el límite del pallet: base ${palletBaseWeight.toFixed(2)} kg + item ${palletBlockedItem.weight.toFixed(2)} kg > ${palletGrossLimit.toFixed(2)} kg.`;
            }
        }
    }

    if (hasContainer && containerGrossLimit > 0) {
        if (hasPallet) {
            const minTopLevelGross = isTrayType
                ? (palletBaseWeight + trayTare + lightestItem.weight)
                : (palletBaseWeight + lightestItem.weight);
            if (minTopLevelGross > containerGrossLimit) {
                return `El contenedor no admite la unidad mínima de carga: ${minTopLevelGross.toFixed(2)} kg > límite de contenedor ${containerGrossLimit.toFixed(2)} kg.`;
            }
        } else if (isTrayType) {
            const minTrayGross = trayTare + lightestItem.weight;
            if (minTrayGross > containerGrossLimit) {
                return `El contenedor no admite una bandeja cargada mínima: ${minTrayGross.toFixed(2)} kg > límite de contenedor ${containerGrossLimit.toFixed(2)} kg.`;
            }
        } else {
            const containerBlockedItem = itemWeights.find(item => item.weight > containerGrossLimit);
            if (containerBlockedItem) {
                return `El item "${containerBlockedItem.name}" pesa ${containerBlockedItem.weight.toFixed(2)} kg y supera el límite del contenedor (${containerGrossLimit.toFixed(2)} kg).`;
            }
        }
    }

    return null;
}

async function calculateLogistics(maximize = false) {
    lastLogisticsMaximize = !!maximize;
    const statusEl = document.getElementById('logistics-status');
    currentLogisticsJobId = null;
    setLogisticsCancelVisibility(false);

    // 0. Gather Config
    const loadType = document.getElementById('logistics-load-type')?.value || 'loose';
    const palletType = document.getElementById('logistics-pallet-type').value;
    const containerType = document.getElementById('logistics-container-type').value;

    // Pallet Height Limit
    let maxPalletHeight = 0;
    const chkLimit = document.getElementById('chk-limit-height');
    if (chkLimit && chkLimit.checked) {
        maxPalletHeight = parseFloat(document.getElementById('pallet-max-height-input').value) || 0;
    }

    // Pallet Weight Limit (Standard Input now)
    let maxPalletWeight = parseFloat(document.getElementById('pallet-max-weight').value) || 0;

    // Gather Custom Pallet Dims
    const trayDims = {
        tray_inner_w: parseFloat(document.getElementById('tray-inner-l')?.value) || 0,
        tray_inner_d: parseFloat(document.getElementById('tray-inner-w')?.value) || 0,
        tray_inner_h: parseFloat(document.getElementById('tray-inner-h')?.value) || 0,
        tray_outer_w: parseFloat(document.getElementById('tray-outer-l')?.value) || 0,
        tray_outer_d: parseFloat(document.getElementById('tray-outer-w')?.value) || 0,
        tray_outer_h: parseFloat(document.getElementById('tray-outer-h')?.value) || 0,
        weight: parseFloat(document.getElementById('tray-weight')?.value) || 0,
        max_weight: parseFloat(document.getElementById('tray-max-weight')?.value) || 25
    };
    const palletDims = {
        w: parseFloat(document.getElementById('pallet-l').value) || 0,
        d: parseFloat(document.getElementById('pallet-w').value) || 0,
        h: parseFloat(document.getElementById('pallet-h').value) || 0,
        weight: parseFloat(document.getElementById('pallet-weight').value) || 0
    };

    // 1. Gather Container Data
    const container = {
        type: containerType,
        name: document.getElementById('logistics-container-type').options[document.getElementById('logistics-container-type').selectedIndex].text,
        width: parseFloat(document.getElementById('cont-l').value) || 0,
        height: parseFloat(document.getElementById('cont-h').value) || 0,
        depth: parseFloat(document.getElementById('cont-w').value) || 0,
        max_weight: parseFloat(document.getElementById('cont-weight').value) || 0
    };

    // 2. Gather Items
    const rows = document.querySelectorAll('#logistics-items-table tbody tr');
    const items = [];

    rows.forEach(row => {
        const name = row.querySelector('.log-name').value;
        const l = parseFloat(row.querySelector('.log-l').value) || 0;
        const w_dim = parseFloat(row.querySelector('.log-w').value) || 0;
        const h = parseFloat(row.querySelector('.log-h').value) || 0;
        const weight = parseFloat(row.querySelector('.log-weight').value) || 0;
        const qty = parseFloat(row.querySelector('.log-qty').value) || 0;
        const relQty = parseFloat(row.querySelector('.log-rel-qty').value) || 0;

        // Check if maximizing with unmixed pallets (each item gets max on own pallet)
        const isMultiItemMax = maximize && containerType === 'none' && palletType !== 'none' && !document.getElementById('chk-mixed-pallets').checked;

        // Allow qty=0 for multi-item maximization mode
        const hasValidQty = isMultiItemMax ? true : (qty > 0 || relQty > 0);

        if (name && l > 0 && w_dim > 0 && h > 0 && hasValidQty) {
            items.push({
                id: name,
                w: l,
                d: w_dim,
                h: h,
                weight: weight > 0 ? weight : 1,
                qty: qty,
                rel_qty: relQty
            });
        }
    });

    if (items.length === 0) {
        statusEl.textContent = 'Ingrese al menos un item válido.';
        return;
    }

    const weightLimitError = validateLogisticsWeightLimits({
        items,
        loadType,
        palletType,
        trayDims,
        palletDims,
        maxPalletWeight,
        container
    });
    if (weightLimitError) {
        statusEl.textContent = '';
        if (typeof showNotification === 'function') {
            showNotification(weightLimitError, 'error');
        } else {
            alert(weightLimitError);
        }
        return;
    }

    statusEl.innerHTML = `<span class="spinner" style="border-top-color: var(--bpb-blue); width: 16px; height: 16px;"></span> ${maximize ? 'Calculando Distribución Máxima...' : 'Calculando...'}`;
    startLogisticsProgress();

    try {
        const startResponse = await fetch('/api/logistics/calculate-start', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                container,
                items,
                config: {
                    maximize: maximize,
                    load_type: loadType,
                    pallet_type: palletType,
                    container_type: containerType,
                    max_pallet_height: maxPalletHeight,
                    max_pallet_weight: maxPalletWeight,
                    tray_dims: trayDims,
                    pallet_dims: palletDims,
                    boards_count: parseInt(document.getElementById('pallet-boards-count')?.value) || 4,
                    safety_factor_dims: parseFloat(document.getElementById('logistics-safety-factor-dims')?.value) || 0,
                    safety_factor_weight: parseFloat(document.getElementById('logistics-safety-factor-weight')?.value) || 0,
                    mixed_trays: document.getElementById('chk-mixed-trays')?.checked ?? true,
                    tray_kanban: document.getElementById('chk-tray-kanban')?.checked ?? false,
                    mixed_pallets: document.getElementById('chk-mixed-pallets')?.checked ?? true,
                    stack_load: true,
                    stack_trays: document.getElementById('chk-stack-trays')?.checked ?? true,
                    stack_collars: document.getElementById('chk-stack-collars')?.checked ?? true,
                    force_orientation: document.getElementById('chk-force-orientation')?.checked ?? false,
                    orientation_face: document.getElementById('logistics-orientation-mode')?.value || 'LxA'
                }
            })
        });

        const startData = await startResponse.json();
        if (startData.status !== 'started' || !startData.job_id) {
            throw new Error(startData.message || 'No se pudo iniciar el cálculo.');
        }
        currentLogisticsJobId = startData.job_id;
        setLogisticsCancelVisibility(true);

        let data = null;
        while (true) {
            await new Promise(resolve => setTimeout(resolve, 500));
            const progressResponse = await fetch(`/api/logistics/calculate-progress/${startData.job_id}`);
            const progressData = await progressResponse.json();
            if (progressData.status === 'running' || progressData.status === 'queued' || progressData.status === 'cancelling') {
                updateLogisticsProgress(
                    progressData.progress || 0,
                    progressData.message || 'Procesando...',
                    progressData.stage || 'queued',
                    progressData.detail || progressData.message || 'Procesando...'
                );
                continue;
            }
            if (progressData.status === 'cancelled') {
                currentLogisticsJobId = null;
                setLogisticsCancelVisibility(false);
                statusEl.textContent = progressData.message || 'Cálculo cancelado.';
                finishLogisticsProgress(false, progressData.message || 'Cálculo cancelado');
                return;
            }
            if (progressData.status === 'done') {
                updateLogisticsProgress(
                    100,
                    progressData.message || 'Cálculo completado',
                    progressData.stage || 'done',
                    progressData.detail || progressData.message || 'Cálculo completado'
                );
                data = progressData.result || null;
                break;
            }
            throw new Error(progressData.message || 'Error durante el cálculo.');
        }

        currentLogisticsJobId = null;
        setLogisticsCancelVisibility(false);

        if (data && data.status === 'success') {
            statusEl.textContent = '';
            lastLogisticsData = data;
            lastContainerData = container;
            window._logisticsPackingDirty = false;

            if (containerType === 'none' && data.bin_dims) {
                lastContainerData = {
                    ...container,
                    width: data.bin_dims.w,
                    height: data.bin_dims.h,
                    depth: data.bin_dims.d,
                    name: "Espacio Virtual"
                };
            }

            if (maximize && data.new_quantities) {
                updateItemQuantities(data.new_quantities);
                statusEl.textContent = 'Maximización completada';
            }

            try {
                renderLogisticsResults(data);
                finishLogisticsProgress(true, 'Completado 100%');
            } catch (renderError) {
                console.error('Render logistics results failed', renderError);
                statusEl.textContent = `Error al renderizar resultados: ${renderError.message || renderError}`;
                finishLogisticsProgress(false, 'Error de visualización');
            }
        } else {
            statusEl.textContent = 'Error: ' + ((data && data.message) || 'Cálculo inválido');
            finishLogisticsProgress(false, 'Cálculo interrumpido');
        }

    } catch (e) {
        console.error(e);
        currentLogisticsJobId = null;
        setLogisticsCancelVisibility(false);
        statusEl.textContent = `Error del cálculo: ${e.message || e}`;
        finishLogisticsProgress(false, 'Cálculo interrumpido');
    }
}

